INSERT INTO comprension_texts (subject_id, level, grades, title, text_content, questions) VALUES
('ingles','eso','{1}','My Bedroom',
'My bedroom is my favourite place in the house. It is not very big, but it is cosy and bright. The walls are light blue and there is a big window next to my bed. On the wall, I have posters of my favourite football players and a map of the world. My bed is in the corner and I have a soft green blanket on it. Next to the bed, there is a small wooden desk where I do my homework every afternoon. On the desk, I keep my laptop, some books, and a cup with pens and pencils. I also have a bookshelf full of adventure novels and comic books. Under the window, there is a brown rug. In the evening, I like to lie on my bed and listen to music. My little dog, Toby, often sleeps at my feet. My bedroom is simple, but I feel happy and calm in it.',
'[{"pregunta":"¿De qué color son las paredes del dormitorio?","opciones":["Verdes","Azul claro","Blancas","Amarillas"],"correcta":1},{"pregunta":"¿Qué hay encima del escritorio?","opciones":["Un televisor","Un portátil, libros y bolígrafos","Una guitarra","Ropa"],"correcta":1},{"pregunta":"¿Dónde duerme el perro Toby?","opciones":["En el suelo","En un sofá","A los pies del niño","Fuera del dormitorio"],"correcta":2},{"pregunta":"¿Qué hace el protagonista por la tarde en su escritorio?","opciones":["Ve películas","Hace los deberes","Come","Duerme"],"correcta":1}]'::jsonb),
('ingles','eso','{1}','Market Day in the Village',
'Every Saturday morning, my grandmother and I go to the market in our small village. The market opens at eight o''clock and there are many colourful stalls. The first stall we visit sells fresh fruit and vegetables. My grandmother always buys tomatoes, lettuce, apples, and oranges. The farmer knows her name and gives me a free strawberry. Next, we go to the cheese stall. There are many different cheeses from the local farms. We usually buy a piece of yellow cheese for breakfast. After that, we walk to the bakery stall and buy warm bread. I love the smell of fresh bread in the morning. My grandmother also stops at the flower stall and buys a small bunch of yellow flowers for the kitchen table. Before going home, we sit on a bench and drink hot chocolate. Saturday is my favourite day of the week because I spend it with my grandmother.',
'[{"pregunta":"¿A qué hora abre el mercado?","opciones":["A las siete","A las ocho","A las nueve","A las diez"],"correcta":1},{"pregunta":"¿Qué le regala el agricultor al niño?","opciones":["Una manzana","Un tomate","Una fresa","Una naranja"],"correcta":2},{"pregunta":"¿Qué compran en la panadería?","opciones":["Pasteles","Pan caliente","Galletas","Croissants"],"correcta":1},{"pregunta":"¿Por qué el sábado es su día favorito?","opciones":["Porque no hay colegio","Porque come chocolate","Porque lo pasa con su abuela","Porque recibe dinero"],"correcta":2}]'::jsonb),
('ingles','eso','{1}','My Best Friend Emma',
'My best friend is Emma. We are both thirteen years old and we go to the same school. Emma has long brown hair and big green eyes. She is tall and very funny. She always tells jokes and makes me laugh. We are in the same class and we sit together during maths and English lessons. Emma is very good at maths, so she helps me with my homework. I am better at drawing, so I help her in art class. After school, we usually go to the park near her house. We play basketball, ride our bikes, or just talk about our favourite TV shows. On Fridays, Emma comes to my house to watch films. We always eat popcorn and drink lemonade. Emma loves animals and she has two cats called Luna and Milo. Next summer, we want to go to the beach together with our families. Emma is not only my best friend, she is like a sister to me.',
'[{"pregunta":"¿Cuántos años tiene Emma?","opciones":["Doce","Trece","Catorce","Quince"],"correcta":1},{"pregunta":"¿En qué asignatura es Emma muy buena?","opciones":["Arte","Educación física","Matemáticas","Música"],"correcta":2},{"pregunta":"¿Qué hacen los viernes en casa del protagonista?","opciones":["Estudian","Ven películas","Juegan al baloncesto","Cocinan"],"correcta":1},{"pregunta":"¿Qué animales tiene Emma?","opciones":["Dos perros","Dos gatos","Un conejo","Un hámster"],"correcta":1}]'::jsonb),
('ingles','eso','{1}','Seasons of the Year',
'There are four seasons in a year: spring, summer, autumn, and winter. Each season is different and special. In spring, the weather gets warmer and the flowers start to grow in the gardens and fields. The trees have new green leaves and many birds return from the south. It sometimes rains, but the rain is usually light. Summer is hot and sunny. Many children go to the beach or the swimming pool with their families. The days are long and people often eat ice cream to feel cool. In autumn, the weather becomes cooler and the leaves on the trees turn yellow, orange, and red. It is a beautiful time to walk in the forest. In winter, the temperature falls and sometimes it snows. People wear warm coats, scarves, and gloves. Children enjoy making snowmen and having snowball fights. Each season brings different activities and makes the year more interesting.',
'[{"pregunta":"¿Qué ocurre en primavera según el texto?","opciones":["Nieva mucho","Las flores empiezan a crecer","Hace mucho frío","Los árboles pierden las hojas"],"correcta":1},{"pregunta":"¿Qué comen las personas en verano para refrescarse?","opciones":["Chocolate","Helado","Sopa","Té caliente"],"correcta":1},{"pregunta":"¿De qué colores son las hojas en otoño?","opciones":["Verdes y azules","Amarillas, naranjas y rojas","Blancas y grises","Solo marrones"],"correcta":1},{"pregunta":"¿Qué hacen los niños en invierno?","opciones":["Van a la playa","Hacen muñecos de nieve","Montan en bici","Recogen flores"],"correcta":1}]'::jsonb),
('ingles','eso','{1}','A Trip to the Zoo',
'Last Sunday, my family and I went to the zoo. We left home early in the morning and took the bus to the city centre. The zoo opened at nine o''clock and there were already many people at the entrance. The first animals we saw were the elephants. They were enormous and one of them sprayed water with its trunk. My little sister was very surprised. Then we visited the monkey area. The monkeys were jumping from tree to tree and making funny noises. My favourite animals were the penguins. They were swimming in cold water and walking on the rocks. I also liked the giraffes because they were very tall and elegant. At lunch time, we had sandwiches and fruit on a wooden table near the lion area. In the afternoon, we watched a show with parrots. They could say words and play with small balls. We went home at six o''clock, tired but very happy.',
'[{"pregunta":"¿En qué medio de transporte fueron al zoo?","opciones":["En coche","En tren","En autobús","En bicicleta"],"correcta":2},{"pregunta":"¿Qué hizo el elefante que sorprendió a la hermana pequeña?","opciones":["Comió una manzana","Echó agua con la trompa","Se durmió","Rugió"],"correcta":1},{"pregunta":"¿Cuáles eran los animales favoritos del narrador?","opciones":["Los monos","Las jirafas","Los pingüinos","Los leones"],"correcta":2},{"pregunta":"¿Qué hacían los loros en el espectáculo?","opciones":["Volaban en círculos","Decían palabras y jugaban con pelotas","Cantaban canciones","Comían plátanos"],"correcta":1}]'::jsonb),
('ingles','eso','{1}','My Grandfather''s Farm',
'My grandfather lives on a small farm in the countryside. Every summer, I visit him for two weeks. His farm is not very big, but it has many animals. There are ten cows, five pigs, twenty chickens, and two horses. My favourite animals are the horses. Their names are Star and Thunder. My grandfather is teaching me how to ride them. Every morning, I wake up early and help my grandfather with the animals. First, we give food to the chickens and collect the fresh eggs. Then, we take the cows to the green fields. After that, we have a big breakfast with fresh milk, bread, butter, and homemade jam. In the afternoon, when it is hot, we sit under a big tree near the house. My grandfather tells me stories about his childhood. In the evening, we eat vegetables from the garden. I love visiting my grandfather because life on the farm is simple and peaceful. I always feel happy there.',
'[{"pregunta":"¿Cuántos caballos hay en la granja?","opciones":["Uno","Dos","Tres","Cinco"],"correcta":1},{"pregunta":"¿Cómo se llaman los caballos?","opciones":["Sol y Luna","Star y Thunder","Rex y Max","Rayo y Viento"],"correcta":1},{"pregunta":"¿Qué hacen primero por la mañana?","opciones":["Riegan las plantas","Dan de comer a las gallinas y recogen huevos","Ordeñan las vacas","Montan a caballo"],"correcta":1},{"pregunta":"¿Dónde se sientan por la tarde cuando hace calor?","opciones":["Dentro de la casa","Bajo un gran árbol","En el granero","En el establo"],"correcta":1}]'::jsonb),
('ingles','eso','{1}','My Hobbies',
'My name is Lucas and I am twelve years old. I have many hobbies and I love doing different activities every day. My favourite hobby is playing the guitar. I started to learn two years ago and now I can play some songs. I practise for thirty minutes every day after school. I also love reading. I usually read adventure books before going to bed. My favourite writer is Roald Dahl because his stories are funny and exciting. Sport is very important for me, so on Tuesdays and Thursdays I play football with my team. We train in the afternoon and we have a match on Saturday. My team is called "The Tigers" and our shirts are orange and black. On Sundays, I go cycling in the forest with my father. We sometimes see rabbits and squirrels. In my free time, I also like drawing cartoons and playing chess with my brother. Hobbies make me happy and they help me to relax.',
'[{"pregunta":"¿Cuál es el hobby favorito de Lucas?","opciones":["Leer","Tocar la guitarra","Jugar al ajedrez","Dibujar"],"correcta":1},{"pregunta":"¿Quién es su escritor favorito?","opciones":["J.K. Rowling","Roald Dahl","Stephen King","Jules Verne"],"correcta":1},{"pregunta":"¿Qué días entrena al fútbol?","opciones":["Lunes y miércoles","Martes y jueves","Viernes y sábado","Solo domingos"],"correcta":1},{"pregunta":"¿Qué hace los domingos con su padre?","opciones":["Juega al ajedrez","Va en bicicleta al bosque","Toca la guitarra","Juega al fútbol"],"correcta":1}]'::jsonb),
('ingles','eso','{1}','The Weather Today',
'The weather in my country is very different depending on the region and the season. In the north, it rains a lot and the temperatures are lower. People usually carry an umbrella because the rain can start at any moment. The landscape is very green because of all the rain. In the south, the weather is much warmer and sunnier. In summer, the temperatures can reach forty degrees Celsius and many tourists visit the beaches. Today, I am in Madrid and the weather is nice. It is sunny but not too hot. The temperature is twenty-two degrees and there is a light wind. I am wearing jeans, a T-shirt, and trainers. I do not need a jacket. The sky is blue with only a few white clouds. Tomorrow, the forecast says it will be cloudy and colder. It might rain in the afternoon, so I will take my raincoat to school. I love checking the weather every morning because it helps me decide what to wear.',
'[{"pregunta":"¿Cómo es el tiempo en el norte del país?","opciones":["Muy caluroso","Lluvioso y más fresco","Seco y nevado","Tropical"],"correcta":1},{"pregunta":"¿Qué temperatura hace hoy en Madrid?","opciones":["Doce grados","Veintidós grados","Treinta y dos grados","Cuarenta grados"],"correcta":1},{"pregunta":"¿Qué lleva puesto el narrador hoy?","opciones":["Un abrigo","Vaqueros, camiseta y zapatillas","Bañador","Botas de agua"],"correcta":1},{"pregunta":"¿Qué tiempo hará mañana?","opciones":["Soleado y caluroso","Nublado y más frío","Nevado","Con niebla"],"correcta":1}]'::jsonb),
('ingles','eso','{1}','Breakfast Around the World',
'Breakfast is the first meal of the day and people eat different things in different countries. In England, a traditional breakfast is very big. It includes eggs, bacon, sausages, beans, toast, and tomatoes. English people also drink tea or coffee with milk. However, many people today only eat cereal or toast because they do not have time in the morning. In Japan, breakfast is very different. Japanese people often eat rice, fish, soup, and vegetables. It is a healthy and light meal. In France, breakfast is usually sweet. People eat croissants, bread with butter and jam, and they drink hot chocolate or coffee. In Spain, children often have milk with cocoa and biscuits or toast with olive oil and tomato. In the United States, pancakes with syrup are very popular, especially on weekends. Breakfast is important because it gives us energy for the whole morning. Doctors say that we should never skip breakfast, even when we are in a hurry.',
'[{"pregunta":"¿Qué incluye un desayuno tradicional inglés?","opciones":["Solo cereales","Huevos, beicon, salchichas, alubias y tostadas","Arroz y pescado","Croissants y mermelada"],"correcta":1},{"pregunta":"¿Cómo es el desayuno en Japón?","opciones":["Muy dulce","Arroz, pescado, sopa y verduras","Solo café","Pan con mermelada"],"correcta":1},{"pregunta":"¿Qué es popular en Estados Unidos, especialmente los fines de semana?","opciones":["Croissants","Tortitas con sirope","Sopa","Fruta"],"correcta":1},{"pregunta":"¿Qué dicen los médicos sobre el desayuno?","opciones":["Que no es importante","Que nunca debemos saltárnoslo","Que solo los niños deben desayunar","Que hay que desayunar poco"],"correcta":1}]'::jsonb),
('ingles','eso','{1}','My Classroom',
'My classroom is on the second floor of the school. It is a big and bright room with three large windows that look out onto the playground. There are twenty-five students in my class and we all sit at small blue desks. The teacher''s desk is at the front of the room, next to a big white board. Behind the teacher, there is a map of Europe and some posters with English verbs. The walls are decorated with our drawings and projects. At the back of the classroom, there is a shelf with dictionaries, story books, and board games. We can use them during break time when the weather is bad. Our classroom also has a small plant called Lily that we water every Monday. My desk is near the window, so I can see the trees and the birds. My best friend sits next to me. I love my classroom because I spend many happy hours there with my friends and my favourite teachers.',
'[{"pregunta":"¿En qué planta está el aula?","opciones":["En la primera","En la segunda","En la tercera","En la planta baja"],"correcta":1},{"pregunta":"¿Cuántos estudiantes hay en la clase?","opciones":["Quince","Veinte","Veinticinco","Treinta"],"correcta":2},{"pregunta":"¿Qué hay en el estante al fondo del aula?","opciones":["Ropa","Diccionarios, libros y juegos de mesa","Comida","Instrumentos musicales"],"correcta":1},{"pregunta":"¿Cuándo riegan la planta del aula?","opciones":["Cada día","Los lunes","Los viernes","Una vez al mes"],"correcta":1}]'::jsonb);

