-- INGLÉS 2º ESO (A1-A2)
-- #############################################################################
INSERT INTO comprension_texts (subject_id, level, grades, title, text_content, questions) VALUES
('ingles','eso','{2}','Our School Trip to Edinburgh',
'Last April, our English teacher organised a school trip to Edinburgh, the capital of Scotland. We were very excited because most of us had never travelled abroad before. The journey was long: we took a coach to the airport, then a plane to Edinburgh, and finally a bus to our hotel. The hotel was small but comfortable and we could see the famous castle from our window. On the first day, we visited Edinburgh Castle and learned about the history of Scotland. The guide told us interesting stories about kings, queens, and battles. On the second day, we walked along the Royal Mile, a long street full of shops, restaurants, and street musicians playing the bagpipes. We tried haggis, a traditional Scottish dish, but not everybody liked it! On the third day, we climbed Arthur''s Seat, a small mountain in the city centre. The view from the top was amazing. We took many photos and videos. The trip lasted four days and it was an unforgettable experience for all of us.',
'[{"pregunta":"¿En qué medio de transporte llegaron a Edimburgo?","opciones":["En tren","En avión","En barco","En coche"],"correcta":1},{"pregunta":"¿Qué visitaron el primer día?","opciones":["El castillo","La universidad","Un museo","La playa"],"correcta":0},{"pregunta":"¿Qué es el haggis?","opciones":["Un postre","Una bebida","Un plato tradicional escocés","Un instrumento"],"correcta":2},{"pregunta":"¿Cuántos días duró el viaje?","opciones":["Tres","Cuatro","Cinco","Una semana"],"correcta":1}]'::jsonb),
('ingles','eso','{2}','My Hobby: Skateboarding',
'I have many hobbies, but my favourite one is skateboarding. I started skateboarding when I was nine years old, after watching a video on the internet. At the beginning, it was very difficult and I fell down many times. My knees and elbows were always full of bruises. However, I did not give up. Now, I am fourteen and I can do many different tricks. I practise every afternoon in the skate park near my house. The skate park is free and there are always other young people there. I have made a lot of friends thanks to skateboarding. We help each other to learn new tricks and we sometimes record videos for our social media accounts. My favourite trick is called the "ollie" because it was the first one I learned. Skateboarding is not just a sport for me, it is a passion. It teaches you patience, courage, and how to keep trying after failure. Next year, I want to participate in a small competition in my city.',
'[{"pregunta":"¿A qué edad empezó a hacer skate?","opciones":["A los siete","A los nueve","A los once","A los catorce"],"correcta":1},{"pregunta":"¿Dónde practica todas las tardes?","opciones":["En el colegio","En el parque de skate","En su casa","En la playa"],"correcta":1},{"pregunta":"¿Cómo se llama su truco favorito?","opciones":["Kickflip","Ollie","Grind","Manual"],"correcta":1},{"pregunta":"¿Qué quiere hacer el año que viene?","opciones":["Dejar el skate","Participar en una competición","Cambiar de hobby","Vender su tabla"],"correcta":1}]'::jsonb),
('ingles','eso','{2}','Italian Food',
'Italian food is one of the most popular cuisines in the world. People love it because it is delicious, healthy, and not too expensive. The most famous Italian dishes are pizza and pasta. Pizza was invented in Naples in the south of Italy. The traditional Margherita pizza has only three ingredients on top: tomato sauce, mozzarella cheese, and fresh basil. The colours represent the Italian flag: red, white, and green. Pasta is also very important in Italian culture. There are more than three hundred types of pasta with different shapes and sizes. Each region of Italy has its own special recipes. For example, in the north, people often eat pasta with creamy sauces, while in the south, they prefer tomato-based sauces with vegetables or seafood. Italians always use fresh ingredients and good quality olive oil. They also love desserts like tiramisu and gelato, which is the Italian word for ice cream. When you visit Italy, you must try the food. It is a very important part of the Italian culture and identity.',
'[{"pregunta":"¿Dónde se inventó la pizza?","opciones":["En Roma","En Milán","En Nápoles","En Florencia"],"correcta":2},{"pregunta":"¿Qué tres ingredientes lleva la pizza Margherita?","opciones":["Queso, jamón y aceitunas","Tomate, mozzarella y albahaca","Champiñones, queso y cebolla","Pollo, maíz y queso"],"correcta":1},{"pregunta":"¿Cuántos tipos de pasta hay aproximadamente?","opciones":["Cien","Doscientos","Más de trescientos","Cincuenta"],"correcta":2},{"pregunta":"¿Qué significa la palabra ''gelato''?","opciones":["Tarta","Helado","Pastel","Yogur"],"correcta":1}]'::jsonb),
('ingles','eso','{2}','My Summer Job',
'Last summer, I had my first job. I am only fifteen years old, so I cannot work in a company, but I helped my uncle in his ice cream shop in the seaside town where my family spends the holidays. The shop is small and very popular among tourists. I worked four hours a day, from six to ten in the evening. My job was to serve customers, prepare cones with different flavours, and clean the tables. At the beginning, I was very nervous because I was afraid of making mistakes. After a few days, I felt more confident and I even started talking to the customers in English when they were tourists from other countries. The most popular flavours were chocolate, strawberry, and vanilla. My favourite was pistachio. My uncle paid me a small salary every week and I saved most of the money to buy a new mobile phone. The experience taught me to be responsible and to value the effort of working. Next summer, I want to help him again.',
'[{"pregunta":"¿Dónde trabajó el narrador?","opciones":["En un restaurante","En la heladería de su tío","En un hotel","En una tienda de ropa"],"correcta":1},{"pregunta":"¿Cuántas horas al día trabajaba?","opciones":["Dos horas","Cuatro horas","Seis horas","Ocho horas"],"correcta":1},{"pregunta":"¿Cuál era su sabor favorito?","opciones":["Chocolate","Fresa","Vainilla","Pistacho"],"correcta":3},{"pregunta":"¿Qué hizo con el dinero que ganó?","opciones":["Lo gastó todo","Ahorró para comprar un móvil","Lo regaló","Lo guardó en el banco"],"correcta":1}]'::jsonb),
('ingles','eso','{2}','Backpacking in Europe',
'Travelling with a backpack is one of the best ways to discover Europe when you are young and you do not have much money. Many students do it during the summer holidays. They travel by train using a special pass called Interrail, which allows them to visit several countries with one ticket. The most popular cities for backpackers are Amsterdam, Berlin, Prague, Vienna, and Barcelona. In each city, young travellers stay in hostels, where they sleep in shared rooms. Hostels are cheap and they are also a great place to meet other young people from different parts of the world. Backpackers usually carry only the basic things: clothes, a toothbrush, a sleeping bag, a water bottle, and a guidebook. They eat in cheap restaurants or buy food in supermarkets and have picnics in the parks. Travelling like this is an adventure. You can change your plans at the last minute, you learn to be independent, and you discover new cultures, languages, and food. Many backpackers say it changed their lives forever.',
'[{"pregunta":"¿Cómo se llama el billete que permite viajar por varios países en tren?","opciones":["Eurail","Interrail","Eurotrip","Backpass"],"correcta":1},{"pregunta":"¿Dónde duermen normalmente los mochileros?","opciones":["En hoteles de lujo","En hostales con habitaciones compartidas","En casas privadas","En camping"],"correcta":1},{"pregunta":"¿Qué llevan en la mochila?","opciones":["Solo ordenadores","Lo básico: ropa, cepillo, saco de dormir, agua y guía","Trajes y zapatos elegantes","Solo dinero"],"correcta":1},{"pregunta":"¿Qué dicen muchos mochileros sobre la experiencia?","opciones":["Que es aburrida","Que les cambió la vida","Que no la repetirían","Que es muy cara"],"correcta":1}]'::jsonb),
('ingles','eso','{2}','Learning a New Hobby: Photography',
'Six months ago, my parents gave me a camera for my birthday. Since then, photography has become my favourite hobby. At first, I did not know how to use the camera properly. I read the manual and watched many tutorials on YouTube. Now I understand the basic concepts: light, focus, and composition. Photography is more complicated than just pressing a button. To take a good picture, you need to think about many things: where the sun is, the colours in the scene, and what you want to show. I love taking photos of nature, especially flowers and birds. On weekends, I go to the park or the countryside with my camera and I spend hours looking for interesting subjects. I also enjoy taking photos of my family and friends, but only when they don''t notice. I think the best photos are the natural ones. I have created an account on a photography website and I share my best pictures there. Some users have left positive comments and that motivates me to keep learning.',
'[{"pregunta":"¿Cuándo recibió la cámara?","opciones":["Hace un año","Hace seis meses","Hace tres meses","La semana pasada"],"correcta":1},{"pregunta":"¿Cómo aprendió a usar la cámara?","opciones":["En un curso","Leyendo el manual y viendo tutoriales","Le enseñó un amigo","Con un libro"],"correcta":1},{"pregunta":"¿Qué tipo de fotos le gusta hacer principalmente?","opciones":["De edificios","De naturaleza, especialmente flores y aves","De coches","De comida"],"correcta":1},{"pregunta":"¿Dónde comparte sus mejores fotos?","opciones":["En una revista","En una web de fotografía","En el instituto","En una exposición"],"correcta":1}]'::jsonb),
('ingles','eso','{2}','Street Food in Asia',
'Asia is famous for its street food. In countries like Thailand, Vietnam, Japan, and India, you can find delicious dishes for very little money in the streets and markets. In Bangkok, the capital of Thailand, the streets are full of small carts where cooks prepare noodles, soups, and grilled meat in front of the customers. One of the most popular dishes is "pad thai", a kind of fried noodle with vegetables, peanuts, and lime. In Vietnam, "pho" is a delicious soup made with rice noodles, beef or chicken, and fresh herbs. People eat it for breakfast, lunch, or dinner. In Japan, you can find small stands selling "takoyaki", little balls of dough with octopus inside. They are cooked on a special hot plate and served with sauce. In India, the streets smell of spices and curry. Street food in Asia is part of the culture and the daily life. Many tourists travel to these countries just to try the food. It is cheap, tasty, and full of flavours and traditions.',
'[{"pregunta":"¿Qué es el pad thai?","opciones":["Una sopa","Un fideo frito con verduras y cacahuetes","Un postre","Una bebida"],"correcta":1},{"pregunta":"¿De qué país es típico el pho?","opciones":["Tailandia","Vietnam","Japón","India"],"correcta":1},{"pregunta":"¿Qué llevan dentro las bolas de takoyaki?","opciones":["Pescado","Pollo","Pulpo","Verduras"],"correcta":2},{"pregunta":"¿Por qué muchos turistas viajan a Asia según el texto?","opciones":["Para hacer compras","Solo para probar la comida","Para ver museos","Para ir a la playa"],"correcta":1}]'::jsonb),
('ingles','eso','{2}','My Cousin Who Lives Abroad',
'My favourite cousin is called Daniel. He is sixteen years old and he lives in Toronto, Canada, with my aunt and uncle. They moved there four years ago because my uncle got a job in a big technology company. At the beginning, it was very hard for Daniel because he did not speak much English. He felt lonely at school and he missed his friends in Spain. After a few months, he made new friends and started to enjoy his new life. Now Daniel is bilingual and he speaks English perfectly. He even has a slight Canadian accent! Every summer, he comes to visit us in Spain for one month. We always have a great time together. We go to the beach, play video games, and ride our bikes. Daniel tells us interesting stories about life in Canada: the cold winters with lots of snow, the friendly people, and the amazing nature. Last year, my family travelled to Toronto for two weeks and we visited the famous Niagara Falls. They are even more beautiful in real life than in the photos.',
'[{"pregunta":"¿Cuántos años tiene Daniel?","opciones":["Catorce","Quince","Dieciséis","Diecisiete"],"correcta":2},{"pregunta":"¿Por qué se mudaron a Canadá?","opciones":["Porque querían viajar","Porque su tío consiguió un trabajo","Porque tenían familia allí","Porque hace buen tiempo"],"correcta":1},{"pregunta":"¿Cómo se sintió Daniel al principio en su nueva escuela?","opciones":["Muy feliz","Solo y echando de menos a sus amigos","Aburrido","Enfadado"],"correcta":1},{"pregunta":"¿Qué visitaron cuando viajaron a Toronto?","opciones":["La Estatua de la Libertad","Las cataratas del Niágara","El Gran Cañón","Las Montañas Rocosas"],"correcta":1}]'::jsonb),
('ingles','eso','{2}','Volunteering at the Animal Shelter',
'Every Saturday morning, I do volunteer work at an animal shelter near my home. The shelter takes care of dogs and cats that have been abandoned or rescued from the streets. There are about fifty animals living there and they all need attention, food, and love. I started volunteering six months ago, after my parents adopted a dog called Bruno from the shelter. I wanted to help other animals find a family too. My job is to clean the cages, refill the water bowls, and take the dogs for walks in a small park nearby. The dogs are always so happy when I arrive. They jump and wag their tails. Sometimes, I also help to bath them. The cats are quieter, but they like to be petted and brushed. The volunteers at the shelter come from different backgrounds: students, retired people, and even children with their parents. We all share one thing in common: we love animals. Volunteering has taught me many things about responsibility, compassion, and teamwork. I encourage other young people to do the same.',
'[{"pregunta":"¿Cuándo va al refugio?","opciones":["Cada día","Los sábados por la mañana","Los domingos por la tarde","Una vez al mes"],"correcta":1},{"pregunta":"¿Por qué empezó a hacer voluntariado?","opciones":["Por obligación del colegio","Porque sus padres adoptaron a Bruno","Para ganar dinero","Para hacer amigos"],"correcta":1},{"pregunta":"¿Cuáles son sus tareas?","opciones":["Vender mascotas","Limpiar jaulas, rellenar bebederos y pasear perros","Solo dar de comer","Atender a la gente"],"correcta":1},{"pregunta":"¿Qué le ha enseñado el voluntariado?","opciones":["A ganar mucho dinero","Responsabilidad, compasión y trabajo en equipo","A ser silencioso","A correr más rápido"],"correcta":1}]'::jsonb),
('ingles','eso','{2}','A Day at a Theme Park',
'Two weeks ago, my family and I spent the whole day at a famous theme park near our city. We arrived at ten in the morning and the place was already full of people. There were long queues in front of every attraction, but we didn''t mind because we were so excited. The first ride we went on was a giant roller coaster called "The Dragon". It was so fast and so high that my little brother was a bit scared, but he loved it in the end. After that, we tried a water ride and we got completely wet. Luckily, the weather was hot and sunny, so it was actually nice. For lunch, we ate hamburgers, chips, and ice cream at one of the restaurants in the park. The food was a bit expensive, but tasty. In the afternoon, we watched a show with acrobats and dancers. It was very impressive. Before going home, we bought some souvenirs at the gift shop: T-shirts, key rings, and a small toy dragon for my brother. We left the park at eight in the evening, exhausted but very happy. It was a perfect day.',
'[{"pregunta":"¿A qué hora llegaron al parque?","opciones":["A las nueve","A las diez","A las once","A las doce"],"correcta":1},{"pregunta":"¿Cómo se llamaba la montaña rusa?","opciones":["The Dragon","The Tiger","The Eagle","The Rocket"],"correcta":0},{"pregunta":"¿Qué pasó en la atracción acuática?","opciones":["Se aburrieron","Se mojaron por completo","Se asustaron","Se cayeron"],"correcta":1},{"pregunta":"¿Qué compró el hermano pequeño como recuerdo?","opciones":["Una camiseta","Un llavero","Un pequeño dragón de juguete","Una taza"],"correcta":2}]'::jsonb);

