-- INGLÉS 4º ESO (A2-B1)
-- #############################################################################
INSERT INTO comprension_texts (subject_id, level, grades, title, text_content, questions) VALUES
('ingles','eso','{4}','The Sinking of the Titanic',
'The RMS Titanic was a British passenger ship that became famous for one of the worst maritime disasters in history. When it was built in Belfast in 1912, the Titanic was the largest and most luxurious ship of its time. Many people called it "unsinkable" because it had advanced safety features and watertight compartments. The ship left Southampton on the tenth of April 1912, on its first voyage across the Atlantic Ocean to New York. There were over two thousand two hundred people on board, including some of the wealthiest passengers of the era. On the night of the fourteenth of April, the Titanic struck an iceberg in the freezing waters of the North Atlantic. The collision opened several holes along the side of the ship, and water quickly began to flood the lower decks. Tragically, there were not enough lifeboats for everyone, and most of the lifeboats were launched only half-full. The ship sank in less than three hours, and around fifteen hundred people lost their lives. The disaster shocked the world and led to important changes in maritime safety regulations, including the requirement to carry enough lifeboats for all passengers and crew.',
'[{"pregunta":"¿Dónde se construyó el Titanic?","opciones":["En Londres","En Belfast","En Southampton","En Liverpool"],"correcta":1},{"pregunta":"¿Por qué llamaban al Titanic ''insumergible''?","opciones":["Porque era pequeño","Por sus características de seguridad y compartimentos estancos","Por su tripulación","Por su velocidad"],"correcta":1},{"pregunta":"¿Cuántas personas perdieron la vida aproximadamente?","opciones":["Quinientas","Mil","Mil quinientas","Dos mil"],"correcta":2},{"pregunta":"¿Qué cambio importante provocó el desastre?","opciones":["Construir barcos más grandes","La obligación de llevar suficientes botes salvavidas","Prohibir los icebergs","Cancelar los viajes transatlánticos"],"correcta":1}]'::jsonb),
('ingles','eso','{4}','Marie Curie: A Scientific Pioneer',
'Marie Curie was one of the most influential scientists of the twentieth century. She was born in Warsaw, Poland, in 1867, at a time when women were not allowed to attend university in her country. Determined to study, she moved to Paris and enrolled at the Sorbonne, where she lived in extreme poverty while completing her studies in physics and mathematics. There, she met her husband Pierre Curie, who shared her passion for research. Together, they discovered two new chemical elements, polonium and radium, and they made major contributions to the study of radioactivity, a term that Marie herself invented. In 1903, she became the first woman ever to receive the Nobel Prize, which she shared with her husband and another scientist for their work on radiation. Eight years later, she won a second Nobel Prize, this time in chemistry, becoming the first person in history to win Nobel Prizes in two different scientific fields. During the First World War, she developed mobile X-ray units to help wounded soldiers on the battlefield. Marie Curie died in 1934 from an illness caused by her long exposure to radioactive materials. Her work opened the door for modern medicine and atomic physics.',
'[{"pregunta":"¿Por qué se mudó Marie Curie a París?","opciones":["Porque le gustaba la ciudad","Porque las mujeres no podían ir a la universidad en Polonia","Por trabajo de su marido","Por motivos de salud"],"correcta":1},{"pregunta":"¿Qué dos elementos descubrió junto a su marido?","opciones":["Uranio y plutonio","Polonio y radio","Mercurio y plata","Oro y cobre"],"correcta":1},{"pregunta":"¿En qué fue la primera de la historia?","opciones":["En ganar Nobel en dos campos científicos diferentes","En estudiar en París","En usar rayos X","En ser polaca"],"correcta":0},{"pregunta":"¿Qué hizo durante la Primera Guerra Mundial?","opciones":["Curó soldados con plantas","Desarrolló unidades móviles de rayos X","Escribió libros","Enseñó en colegios"],"correcta":1}]'::jsonb),
('ingles','eso','{4}','The Power of Vaccines',
'Vaccines are one of the most important medical discoveries in history. They have saved millions of lives and protected humanity from many dangerous diseases. The first vaccine was created in 1796 by an English doctor called Edward Jenner. He noticed that women who worked with cows and caught a mild illness called cowpox never developed smallpox, a much more serious disease. Based on this observation, he successfully experimented with a young boy and created the first vaccine in history. Smallpox, which had killed hundreds of millions of people throughout history, was officially declared eradicated in 1980, thanks to vaccination campaigns around the world. Today, children are vaccinated against many illnesses such as measles, polio, tetanus, and tuberculosis. Vaccines work by teaching the immune system to recognise and fight specific viruses or bacteria. Although some people still doubt their safety, scientific evidence is clear: vaccines are safe and effective. During the recent COVID-19 pandemic, vaccines were developed in record time and helped to control the spread of the virus, saving millions of lives. The work of scientists, doctors, and nurses around the world made this possible. Vaccination remains one of humanity''s greatest weapons against disease.',
'[{"pregunta":"¿Quién creó la primera vacuna y cuándo?","opciones":["Marie Curie en 1900","Edward Jenner en 1796","Louis Pasteur en 1850","Alexander Fleming en 1928"],"correcta":1},{"pregunta":"¿Cuándo se declaró erradicada la viruela?","opciones":["En 1796","En 1900","En 1980","En 2000"],"correcta":2},{"pregunta":"¿Cómo funcionan las vacunas?","opciones":["Curan directamente la enfermedad","Enseñan al sistema inmune a reconocer y combatir virus o bacterias","Eliminan los síntomas","Aumentan la temperatura"],"correcta":1},{"pregunta":"¿Qué pasó con las vacunas durante la pandemia de COVID-19?","opciones":["No funcionaron","Se desarrollaron en tiempo récord","Tardaron veinte años","Se prohibieron"],"correcta":1}]'::jsonb),
('ingles','eso','{4}','Equal Rights for Women',
'The fight for equal rights for women is one of the most important social movements in modern history. For centuries, women in most societies had very few rights. They could not vote, could not study at universities, and could not own property. They were expected to stay at home, take care of the children, and obey their husbands. In the late nineteenth century, a movement called the suffragettes began in the United Kingdom and the United States. Brave women like Emmeline Pankhurst and Susan B. Anthony organised protests, marches, and even hunger strikes to demand the right to vote. Many of them were arrested and sent to prison, but they did not give up. Their efforts were finally rewarded: women obtained the right to vote in many countries during the early twentieth century. However, the fight for equality did not end there. Throughout the twentieth and twenty-first centuries, women have continued to struggle for equal pay, equal opportunities at work, education, and protection against discrimination and violence. Although a lot of progress has been made, gender equality has still not been fully achieved. There are still countries where girls are not allowed to attend school or where women earn less than men for the same job. The fight continues today in every corner of the world.',
'[{"pregunta":"¿Cómo se llamaba el movimiento que luchó por el voto femenino?","opciones":["Las feministas","Las sufragistas","Las socialistas","Las activistas"],"correcta":1},{"pregunta":"¿Qué métodos usaban estas mujeres?","opciones":["Votaban en secreto","Protestas, marchas y huelgas de hambre","Solo escribían cartas","Hacían fiestas"],"correcta":1},{"pregunta":"¿Qué problemas siguen existiendo según el texto?","opciones":["Ninguno, ya hay igualdad","Brechas salariales y discriminación en algunos países","Solo en deportes","Solo en política"],"correcta":1},{"pregunta":"¿Quiénes son citadas como líderes del movimiento?","opciones":["Marie Curie y Frida Kahlo","Emmeline Pankhurst y Susan B. Anthony","Margaret Thatcher y Angela Merkel","Rosa Parks y Malala"],"correcta":1}]'::jsonb),
('ingles','eso','{4}','The Origin of Cinema',
'Cinema is one of the most popular forms of entertainment in the modern world, but it did not exist before the late nineteenth century. The history of cinema began in 1895, when two French brothers, Auguste and Louis Lumière, organised the first public film projection in Paris. They had invented a machine called the "cinématographe", which could record, project, and develop moving images. The first films lasted only a few seconds and showed simple scenes from everyday life, such as workers leaving a factory or a train arriving at a station. The audience was completely amazed: it was the first time they had ever seen moving pictures on a screen. In the early years, films were silent and in black and white. Music was played live in the cinema by a pianist or a small orchestra. The first films with synchronised sound, called "talkies", appeared in the late 1920s and changed the industry forever. Soon after, colour films also became common. Today, cinema is a global industry worth billions of dollars. Hollywood, in California, has been the centre of the film industry for almost a century, but other countries like India, with its famous Bollywood, also produce thousands of films every year. From its humble beginnings, cinema has become an art form that influences cultures all around the world.',
'[{"pregunta":"¿Cuándo se hizo la primera proyección pública de cine?","opciones":["En 1885","En 1895","En 1905","En 1915"],"correcta":1},{"pregunta":"¿Cómo se llamaba la máquina inventada por los hermanos Lumière?","opciones":["Cinematógrafo","Kinetoscopio","Fonógrafo","Daguerrotipo"],"correcta":0},{"pregunta":"¿Cómo eran los primeros cines en cuanto al sonido?","opciones":["Tenían sonido grabado","Eran silentes con música en directo","Tenían diálogos","Tenían efectos digitales"],"correcta":1},{"pregunta":"¿Cómo se llama la industria del cine en la India?","opciones":["Hollywood","Bollywood","Tollywood","Mollywood"],"correcta":1}]'::jsonb),
('ingles','eso','{4}','Renewable Energy',
'Renewable energy is energy obtained from natural sources that are constantly replenished, such as sunlight, wind, water, and geothermal heat. Unlike fossil fuels like oil, coal, and gas, renewable sources do not run out and they produce much less pollution. As the world faces the dangerous consequences of climate change, the transition to renewable energy has become more urgent than ever. Solar panels are now installed on the roofs of millions of houses around the world. They convert sunlight directly into electricity, and they have become much cheaper in the last decade. Wind turbines, which look like giant fans, are another important source of clean energy. They are usually built in places with strong winds, either on land or out at sea. Hydropower, generated by the movement of water in rivers and dams, is one of the oldest and most reliable renewable sources. Many countries are also investing in geothermal energy, which uses the natural heat from inside the Earth. Switching to renewable energy is essential, but it is not easy. It requires huge investments and political decisions. However, the benefits are clear: cleaner air, fewer greenhouse gases, and a more sustainable future for our planet. Some countries, like Iceland and Norway, already produce most of their electricity from renewable sources.',
'[{"pregunta":"¿Qué son las energías renovables?","opciones":["Energías baratas","Energías obtenidas de fuentes naturales que se reponen constantemente","Energías que se acaban","Energías nucleares"],"correcta":1},{"pregunta":"¿Qué hacen los paneles solares?","opciones":["Calientan agua solamente","Convierten la luz solar en electricidad","Producen viento","Generan calor geotérmico"],"correcta":1},{"pregunta":"¿Cuál es una de las fuentes renovables más antiguas y fiables?","opciones":["La solar","La hidroeléctrica","La geotérmica","La nuclear"],"correcta":1},{"pregunta":"¿Qué países ya producen la mayor parte de su electricidad con renovables?","opciones":["España y Portugal","Islandia y Noruega","China y Japón","Estados Unidos y México"],"correcta":1}]'::jsonb),
('ingles','eso','{4}','The Berlin Wall',
'The Berlin Wall was one of the most powerful symbols of the Cold War, the long period of tension between the United States and the Soviet Union after the Second World War. After the war, Germany was divided into two countries: West Germany, which was democratic and supported by the western powers, and East Germany, which was communist and controlled by the Soviet Union. The capital, Berlin, was also divided in two, although it was located inside East Germany. Many citizens of East Germany were unhappy with the communist regime and tried to escape to the western part of the city. To stop them, the East German government built a wall around West Berlin in August 1961. The Berlin Wall stretched for over 150 kilometres and was guarded by soldiers with orders to shoot anyone who tried to cross. For almost three decades, the wall separated families, friends, and neighbours. At least 140 people died trying to cross it. Finally, on the ninth of November 1989, the wall fell. Thousands of people from both sides celebrated together, hugging strangers and breaking pieces of the wall as souvenirs. The fall of the Berlin Wall marked the beginning of the end of the Cold War and the reunification of Germany the following year. Today, only a few sections of the wall remain as a reminder of this dramatic period.',
'[{"pregunta":"¿Por qué se construyó el muro?","opciones":["Para proteger Berlín del ataque","Para impedir que los habitantes del este escaparan al oeste","Por motivos turísticos","Para señalar la frontera"],"correcta":1},{"pregunta":"¿En qué año se construyó el muro?","opciones":["En 1945","En 1961","En 1975","En 1989"],"correcta":1},{"pregunta":"¿Cuántos kilómetros medía aproximadamente?","opciones":["50","100","Más de 150","500"],"correcta":2},{"pregunta":"¿Cuándo cayó el muro?","opciones":["El 9 de noviembre de 1989","El 1 de enero de 1990","El 14 de julio de 1989","El 25 de diciembre de 1990"],"correcta":0}]'::jsonb),
('ingles','eso','{4}','Genetic Engineering',
'Genetic engineering is one of the most fascinating and controversial fields of modern science. It refers to the process of changing the DNA of living organisms in order to give them new characteristics. Scientists can now modify plants, animals, and even bacteria in laboratories. The first genetically modified food was a tomato, created in the 1990s, which could stay fresh for longer periods. Today, many crops, including corn, soybeans, and cotton, have been genetically modified to resist insects, diseases, or drought. Supporters argue that these crops can help solve the problem of world hunger, especially in poor countries with difficult climate conditions. They also produce larger harvests with less use of pesticides. However, critics worry about the long-term effects on human health and the environment. Some fear that genetically modified plants might damage other species or create new allergies. Genetic engineering also has important applications in medicine. Scientists are now able to produce insulin for diabetic patients using modified bacteria, and they are researching ways to cure inherited diseases by repairing damaged genes. Recently, a new technique called CRISPR has revolutionised this field, making genetic modifications faster, cheaper, and more precise. The ethical questions raised by these advances are profound and society will need to discuss them carefully.',
'[{"pregunta":"¿Cuál fue el primer alimento modificado genéticamente?","opciones":["El maíz","Un tomate","La soja","El arroz"],"correcta":1},{"pregunta":"¿Qué dicen los defensores de los cultivos modificados?","opciones":["Que son peligrosos","Que pueden ayudar a resolver el hambre y producen cosechas mayores","Que son más caros","Que no funcionan"],"correcta":1},{"pregunta":"¿Qué se puede producir hoy con bacterias modificadas?","opciones":["Petróleo","Insulina para diabéticos","Plástico","Oro"],"correcta":1},{"pregunta":"¿Qué técnica reciente ha revolucionado este campo?","opciones":["DNA-X","CRISPR","NANO","BIO-TECH"],"correcta":1}]'::jsonb),
('ingles','eso','{4}','The Influence of Music in Society',
'Music has been an essential part of human society since the very beginning of civilization. Every culture in the world has its own musical traditions, instruments, and styles. Music is not just entertainment: it has the power to influence emotions, bring people together, and even change history. Throughout the twentieth century, popular music played a major role in important social movements. In the 1960s, artists like Bob Dylan and John Lennon used their songs to protest against the Vietnam War and to promote messages of peace. Reggae music, born in Jamaica, became a symbol of resistance and freedom thanks to legendary singers like Bob Marley. In Spain, "Cantautores" used their lyrics to criticise dictatorship during the years of Franco. Today, music continues to influence society in many different ways. Hip hop and rap, for instance, often deal with serious social issues such as racism, poverty, and inequality. Music is also a global business worth billions of euros. Streaming platforms like Spotify and YouTube have changed the way we discover and listen to music. Artists no longer need to sell physical albums to be successful. They can reach millions of fans around the world from their bedrooms. Despite these enormous changes, the magic of music remains the same: it connects people, expresses emotions, and tells stories that words alone cannot.',
'[{"pregunta":"¿Qué cantantes se mencionan como protestantes contra la guerra de Vietnam?","opciones":["Bob Marley y Elvis","Bob Dylan y John Lennon","Madonna y Michael Jackson","Los Beatles y Rolling Stones"],"correcta":1},{"pregunta":"¿De qué país nace el reggae?","opciones":["Estados Unidos","Cuba","Jamaica","Brasil"],"correcta":2},{"pregunta":"¿Qué temas trata frecuentemente el rap según el texto?","opciones":["Solo amor","Racismo, pobreza y desigualdad","Naturaleza","Deporte"],"correcta":1},{"pregunta":"¿Cómo han cambiado las cosas las plataformas de streaming?","opciones":["Han eliminado a los artistas","Permiten llegar a millones de fans sin vender discos físicos","Han subido los precios","Han prohibido la música nueva"],"correcta":1}]'::jsonb),
('ingles','eso','{4}','The Role of Volunteering',
'Volunteering is the act of giving your time and skills to help others without expecting any payment in return. Around the world, millions of people of all ages choose to do volunteer work in their communities. They help in many different areas: feeding the homeless, teaching children in disadvantaged neighbourhoods, taking care of the elderly, protecting wildlife, or organising events. Volunteering brings huge benefits, both to the people who receive help and to the volunteers themselves. By working with others, volunteers develop important skills like teamwork, communication, leadership, and problem-solving. They also learn about different cultures and realities, and they often discover their true passions and vocations. Many universities and companies value voluntary experience when selecting students or employees, because it shows commitment, generosity, and personal initiative. In recent years, there has been a growing movement of young volunteers all over the world. International organisations such as the Red Cross, Greenpeace, and UNICEF rely on the dedication of millions of volunteers to carry out their important work. There are also opportunities to volunteer abroad, helping in conservation projects in Africa, building schools in Asia, or working with refugees in Europe. Volunteering reminds us that small acts of kindness can make a big difference and that we are all part of the same human family.',
'[{"pregunta":"¿Qué es el voluntariado?","opciones":["Un trabajo bien pagado","Dar tiempo y habilidades para ayudar sin recibir pago","Una obligación","Un curso universitario"],"correcta":1},{"pregunta":"¿Qué habilidades desarrollan los voluntarios?","opciones":["Solo manuales","Trabajo en equipo, comunicación, liderazgo y resolución de problemas","Solo idiomas","Solo deporte"],"correcta":1},{"pregunta":"¿Por qué las universidades y empresas valoran la experiencia voluntaria?","opciones":["Porque es obligatoria","Porque demuestra compromiso, generosidad e iniciativa","Porque es divertida","Porque es barata"],"correcta":1},{"pregunta":"¿Qué organizaciones internacionales se mencionan?","opciones":["FBI, CIA, Interpol","Cruz Roja, Greenpeace y UNICEF","ONU, OTAN, OEA","Apple, Google, Amazon"],"correcta":1}]'::jsonb);

