INSERT INTO comprension_texts (subject_id, level, grades, title, text_content, questions) VALUES
('frances','eso','{1}','Ma chambre',
'Bonjour ! Je m''appelle Léa et j''ai douze ans. Je vais vous décrire ma chambre. Ma chambre n''est pas très grande, mais elle est jolie et confortable. Les murs sont roses et il y a un grand poster de chats sur le mur près de mon lit. Mon lit est petit et il y a une couverture violette dessus. À côté du lit, il y a une petite table avec une lampe et mon réveil. Devant la fenêtre, il y a un bureau en bois où je fais mes devoirs tous les jours après l''école. Sur le bureau, il y a mes cahiers, mes stylos et mon ordinateur portable. À droite, il y a une grande armoire blanche avec tous mes vêtements. J''ai aussi une étagère avec beaucoup de livres et de jouets. Au sol, il y a un petit tapis bleu très doux. J''adore ma chambre parce que c''est mon endroit préféré pour lire, écouter de la musique et me reposer. Le soir, mon chat Minou dort souvent sur mon lit avec moi.',
'[{"pregunta":"¿De qué color son las paredes de la habitación?","opciones":["Azules","Rosas","Blancas","Verdes"],"correcta":1},{"pregunta":"¿Qué hay encima del escritorio?","opciones":["Una televisión","Cuadernos, bolígrafos y un portátil","Ropa","Juguetes"],"correcta":1},{"pregunta":"¿De qué color es la alfombra?","opciones":["Roja","Verde","Azul","Amarilla"],"correcta":2},{"pregunta":"¿Quién duerme con Léa por la noche?","opciones":["Su hermano","Su perro","Su gato Minou","Nadie"],"correcta":2}]'::jsonb),
('frances','eso','{1}','Ma famille',
'Je m''appelle Thomas et j''ai onze ans. Je vais vous présenter ma famille. Ma famille n''est pas très grande. Nous sommes cinq personnes à la maison. Mon père s''appelle Pierre et il a quarante-deux ans. Il est ingénieur et il travaille dans un bureau en ville. Ma mère s''appelle Sophie et elle a quarante ans. Elle est professeur de mathématiques au collège. J''ai un frère et une soeur. Mon frère s''appelle Lucas et il a quinze ans. Il aime le football et il joue dans une équipe le samedi. Ma petite soeur s''appelle Émilie. Elle a seulement six ans et elle est très drôle. Elle adore dessiner et chanter. Nous avons aussi un chien qui s''appelle Rex. Il est marron et blanc, et il est très gentil. Le dimanche, toute la famille mange ensemble chez ma grand-mère. Elle habite dans un petit village à la campagne et elle prépare toujours un délicieux gâteau au chocolat. J''aime beaucoup ma famille parce que nous sommes très unis.',
'[{"pregunta":"¿Cuántas personas viven en casa de Thomas?","opciones":["Tres","Cuatro","Cinco","Seis"],"correcta":2},{"pregunta":"¿Cuál es la profesión de la madre?","opciones":["Ingeniera","Profesora de matemáticas","Médica","Cocinera"],"correcta":1},{"pregunta":"¿Qué le gusta hacer a Émilie?","opciones":["Jugar al fútbol","Dibujar y cantar","Estudiar","Cocinar"],"correcta":1},{"pregunta":"¿Qué prepara la abuela los domingos?","opciones":["Una pizza","Una sopa","Un pastel de chocolate","Una ensalada"],"correcta":2}]'::jsonb),
('frances','eso','{1}','À l''école',
'Je m''appelle Camille et je suis élève au collège Jules Verne, à Lyon. Mon école est grande et moderne. Il y a beaucoup de salles de classe, une cantine, un gymnase et une bibliothèque. Les cours commencent à huit heures du matin et finissent à quatre heures et demie. J''ai cours du lundi au vendredi. Mes matières préférées sont l''anglais et les sciences. Je n''aime pas trop les mathématiques parce que c''est difficile pour moi. À midi, je mange à la cantine avec mes amis. La nourriture est généralement bonne. Aujourd''hui, par exemple, il y a du poulet avec des frites et une salade. Pendant la récréation, je joue au basket avec mes camarades dans la cour. J''ai beaucoup d''amis à l''école, mais ma meilleure amie s''appelle Julie. Nous sommes dans la même classe et nous nous asseyons à côté l''une de l''autre. Après les cours, je rentre à la maison à pied parce que j''habite près de l''école. Le soir, je fais mes devoirs et je révise mes leçons. J''aime mon école.',
'[{"pregunta":"¿Cómo se llama el colegio?","opciones":["Victor Hugo","Jules Verne","Voltaire","Molière"],"correcta":1},{"pregunta":"¿A qué hora terminan las clases?","opciones":["A las cuatro","A las cuatro y media","A las cinco","A las cinco y media"],"correcta":1},{"pregunta":"¿Cuáles son sus asignaturas favoritas?","opciones":["Matemáticas y francés","Inglés y ciencias","Historia y arte","Música y deporte"],"correcta":1},{"pregunta":"¿Cómo vuelve a casa después de clase?","opciones":["En autobús","En bicicleta","Andando","En coche"],"correcta":2}]'::jsonb),
('frances','eso','{1}','Mes goûts alimentaires',
'Salut ! Je m''appelle Hugo et j''ai treize ans. Je vais vous parler de ce que j''aime et de ce que je n''aime pas manger. Pour le petit déjeuner, je prends toujours un bol de céréales avec du lait et un jus d''orange. Le matin, j''aime aussi manger des tartines avec du beurre et de la confiture de fraises. À midi, je mange à la cantine de l''école. Mon plat préféré, c''est les pâtes à la sauce tomate. J''adore aussi la pizza, surtout celle au fromage. Je n''aime pas du tout les épinards parce qu''ils sont amers. Pour le goûter, à quatre heures, je mange souvent un croissant ou un pain au chocolat. Le soir, ma mère prépare le dîner. Elle cuisine très bien. Souvent, nous mangeons du poisson avec des légumes ou de la soupe. Mon dessert préféré, c''est la mousse au chocolat. J''adore le chocolat ! Je n''aime pas beaucoup les fruits, mais je sais qu''ils sont importants pour la santé. Alors, je mange une banane ou une pomme presque tous les jours. Et toi, qu''est-ce que tu aimes manger ?',
'[{"pregunta":"¿Qué desayuna Hugo normalmente?","opciones":["Un café y galletas","Cereales con leche y zumo de naranja","Solo fruta","Tostadas con jamón"],"correcta":1},{"pregunta":"¿Cuál es su plato favorito?","opciones":["La pizza","Las espinacas","La pasta con tomate","La sopa"],"correcta":2},{"pregunta":"¿Qué no le gusta nada?","opciones":["El chocolate","Los espinacas","La pizza","Las pastas"],"correcta":1},{"pregunta":"¿Cuál es su postre favorito?","opciones":["Yogur","Mousse de chocolate","Helado","Tarta de manzana"],"correcta":1}]'::jsonb),
('frances','eso','{1}','Une journée à la plage',
'Aujourd''hui, c''est dimanche et il fait très beau. Toute ma famille décide d''aller à la plage. Nous habitons à Marseille, donc la mer est proche. Nous préparons un grand sac avec les serviettes, la crème solaire, les maillots de bain et un pique-nique. Mon père conduit la voiture et nous arrivons à la plage à dix heures. Il y a déjà beaucoup de monde. L''eau est bleue et le sable est chaud. Ma soeur et moi, nous courons tout de suite dans l''eau. Elle est un peu froide au début, mais c''est très agréable. Nous nageons et nous jouons avec un ballon. Ma mère préfère lire un livre sous le parasol. Mon père aime se promener au bord de l''eau. À midi, nous mangeons des sandwichs, des chips et des fruits. C''est délicieux ! L''après-midi, je construis un grand château de sable avec ma soeur. Nous décorons notre château avec des coquillages. Vers cinq heures, nous rentrons à la maison. Je suis fatigué mais très content. J''aime beaucoup les journées à la plage avec ma famille.',
'[{"pregunta":"¿Dónde vive la familia?","opciones":["En París","En Marsella","En Lyon","En Niza"],"correcta":1},{"pregunta":"¿A qué hora llegan a la playa?","opciones":["A las nueve","A las diez","A las once","A las doce"],"correcta":1},{"pregunta":"¿Qué prefiere hacer la madre?","opciones":["Nadar","Leer un libro bajo la sombrilla","Jugar al balón","Pasear"],"correcta":1},{"pregunta":"¿Con qué decoran el castillo de arena?","opciones":["Con flores","Con conchas","Con piedras","Con palos"],"correcta":1}]'::jsonb),
('frances','eso','{1}','Mon meilleur ami',
'Mon meilleur ami s''appelle Maxime. Il a douze ans, comme moi. Nous nous connaissons depuis l''école primaire et nous sommes toujours dans la même classe. Maxime est grand et mince. Il a les cheveux courts et bruns, et les yeux verts. Il porte des lunettes parce qu''il ne voit pas très bien de loin. Maxime est très intelligent et drôle. Il fait toujours rire toute la classe avec ses blagues. Il habite près de chez moi, à seulement deux rues. Après l''école, nous faisons nos devoirs ensemble chez lui ou chez moi. Maxime adore les jeux vidéo, surtout les jeux d''aventure. Moi aussi, j''aime jouer aux jeux vidéo, alors nous passons beaucoup de temps à jouer ensemble. Le week-end, nous allons souvent au parc faire du vélo ou jouer au foot avec d''autres amis. Maxime est aussi très gentil. Quand j''ai un problème, il m''écoute toujours. L''année dernière, j''étais malade et il est venu me voir tous les jours pour m''apporter mes devoirs. C''est un véritable ami, et j''espère que nous serons amis toute notre vie.',
'[{"pregunta":"¿Desde cuándo se conocen Maxime y el narrador?","opciones":["Desde el año pasado","Desde la escuela primaria","Desde el verano","Desde hace dos meses"],"correcta":1},{"pregunta":"¿De qué color son los ojos de Maxime?","opciones":["Azules","Verdes","Marrones","Grises"],"correcta":1},{"pregunta":"¿Qué le gusta mucho a Maxime?","opciones":["La música","Los videojuegos de aventura","El cine","La cocina"],"correcta":1},{"pregunta":"¿Qué hizo Maxime cuando el narrador estaba enfermo?","opciones":["Lo llamó por teléfono","Le llevó los deberes todos los días","Le envió un email","Nada"],"correcta":1}]'::jsonb),
('frances','eso','{1}','Mon animal préféré',
'J''adore les animaux. Mon animal préféré est le dauphin. Les dauphins sont des animaux très intelligents et sociables qui vivent dans la mer. Ils sont gris ou bleus et ils ont une peau lisse. Les dauphins peuvent nager très vite et ils sautent souvent hors de l''eau. C''est très impressionnant ! Ils mangent du poisson et ils vivent en groupes appelés "bancs". Les dauphins communiquent entre eux avec des sons spéciaux, comme une langue secrète. Les scientifiques disent qu''ils sont aussi intelligents que les chimpanzés. À la maison, j''ai aussi un animal de compagnie. C''est un petit chien blanc qui s''appelle Bobby. Il a deux ans et il est très joueur. Tous les jours, je le promène dans le parc à côté de chez moi. Bobby aime courir et attraper la balle que je lui lance. Le soir, il dort dans son panier dans le salon. Je prends bien soin de lui. Je voudrais aussi avoir un poisson rouge et un hamster, mais mes parents disent que c''est suffisant pour le moment. J''aime tous les animaux et je voudrais devenir vétérinaire quand je serai grand.',
'[{"pregunta":"¿Cuál es el animal favorito del narrador?","opciones":["El perro","El delfín","El gato","El hámster"],"correcta":1},{"pregunta":"¿Qué comen los delfines?","opciones":["Plantas","Pescado","Frutas","Insectos"],"correcta":1},{"pregunta":"¿Cómo se llama su perro?","opciones":["Rex","Bobby","Max","Toby"],"correcta":1},{"pregunta":"¿Qué quiere ser de mayor?","opciones":["Profesor","Veterinario","Médico","Biólogo"],"correcta":1}]'::jsonb),
('frances','eso','{1}','Mon anniversaire',
'Mon anniversaire est le quinze mars. Cette année, j''ai eu treize ans. Pour fêter mon anniversaire, j''ai organisé une petite fête à la maison avec mes meilleurs amis. J''ai invité huit personnes : quatre filles et quatre garçons. La fête a commencé à quatre heures de l''après-midi. Ma mère a préparé beaucoup de bonnes choses : des pizzas, des sandwichs, des chips, des bonbons et des boissons. Mais le plus important, c''était le gâteau d''anniversaire ! C''était un gâteau au chocolat avec des fraises et il y avait treize bougies dessus. Quand j''ai soufflé les bougies, tout le monde a chanté "Joyeux anniversaire". Ensuite, j''ai ouvert mes cadeaux. Mes parents m''ont offert un nouveau vélo. C''est le plus beau cadeau du monde ! Mes amis m''ont donné des livres, un jeu vidéo, des bonbons et un t-shirt de mon équipe de foot préférée. Après les cadeaux, nous avons dansé et joué à des jeux. Nous avons aussi regardé un film amusant. La fête s''est terminée à neuf heures du soir. C''était une journée fantastique et je n''oublierai jamais mes treize ans !',
'[{"pregunta":"¿Cuándo es su cumpleaños?","opciones":["El 5 de marzo","El 15 de marzo","El 25 de marzo","El 15 de mayo"],"correcta":1},{"pregunta":"¿Cuántos invitados había?","opciones":["Cinco","Seis","Ocho","Diez"],"correcta":2},{"pregunta":"¿Qué le regalaron sus padres?","opciones":["Un libro","Una bicicleta nueva","Un videojuego","Una camiseta"],"correcta":1},{"pregunta":"¿A qué hora terminó la fiesta?","opciones":["A las siete","A las ocho","A las nueve","A las diez"],"correcta":2}]'::jsonb),
('frances','eso','{1}','Le matin chez moi',
'Du lundi au vendredi, je me lève tôt parce que je vais à l''école. Mon réveil sonne à sept heures. Au début, j''ai un peu de mal à me lever, mais je sais que je dois me dépêcher. D''abord, je vais dans la salle de bains. Je me lave le visage avec de l''eau froide pour me réveiller, je me brosse les dents et je me peigne. Ensuite, je m''habille. En hiver, je porte un pull et un pantalon chaud. En été, je préfère un t-shirt et un short. Après, je descends à la cuisine pour le petit déjeuner. Toute la famille mange ensemble. Mon père prend un café noir et lit le journal. Ma mère boit du thé avec du citron. Mon petit frère et moi, nous mangeons des céréales avec du lait et nous buvons un jus d''orange. Vers sept heures et demie, je prends mon sac à dos et je sors de la maison. L''école est à quinze minutes à pied. J''aime marcher le matin parce que l''air est frais et il y a peu de voitures. J''arrive à l''école à huit heures moins le quart, juste à temps pour les cours.',
'[{"pregunta":"¿A qué hora suena el despertador?","opciones":["A las seis","A las siete","A las ocho","A las nueve"],"correcta":1},{"pregunta":"¿Qué bebe el padre por la mañana?","opciones":["Té con limón","Café negro","Zumo de naranja","Leche"],"correcta":1},{"pregunta":"¿Qué desayuna el narrador?","opciones":["Tostadas con mantequilla","Cereales con leche y zumo de naranja","Croissants","Solo fruta"],"correcta":1},{"pregunta":"¿Cuánto tarda en llegar a la escuela andando?","opciones":["Cinco minutos","Diez minutos","Quince minutos","Veinte minutos"],"correcta":2}]'::jsonb),
('frances','eso','{1}','Le marché du samedi',
'Tous les samedis matin, je vais au marché avec ma mère. Le marché de notre ville est sur la grande place, devant la mairie. Il commence à huit heures et il finit à treize heures. Il y a beaucoup de stands différents et c''est très coloré. Il y a des stands de fruits et de légumes, des stands de fromage, de pain, de viande et de poisson. On trouve aussi des fleurs, des vêtements et des objets pour la maison. Ma mère achète toujours des tomates, des carottes, des pommes de terre et des oranges chez le même vendeur. Il s''appelle Monsieur Dupont et il est très gentil. Il connaît ma mère depuis longtemps et il me donne toujours une pomme gratuite. Ensuite, nous allons à la boulangerie pour acheter une baguette fraîche et des croissants pour le petit déjeuner du dimanche. J''adore l''odeur du pain chaud ! Avant de rentrer à la maison, nous nous arrêtons dans un café pour boire un chocolat chaud. C''est mon moment préféré. J''aime beaucoup le marché parce que c''est animé, il y a beaucoup de couleurs et beaucoup d''odeurs agréables.',
'[{"pregunta":"¿Dónde está el mercado?","opciones":["En la plaza, delante del ayuntamiento","En el parque","Cerca del río","En la calle principal"],"correcta":0},{"pregunta":"¿Cómo se llama el vendedor de frutas?","opciones":["Sr. Martin","Sr. Dupont","Sr. Bernard","Sr. Petit"],"correcta":1},{"pregunta":"¿Qué compran en la panadería?","opciones":["Pasteles","Pan y croissants","Galletas","Tartas"],"correcta":1},{"pregunta":"¿Qué hacen antes de volver a casa?","opciones":["Ir al cine","Tomar un chocolate caliente en un café","Pasear por el parque","Ir de compras a una tienda"],"correcta":1}]'::jsonb);

