INSERT INTO comprension_texts (subject_id, level, grades, title, text_content, questions) VALUES
('valenciano','eso','{2}','La Tomatina de Bunyol',
'La Tomatina és una de les festes més originals i divertides del món. Se celebra cada any l''últim dimecres del mes d''agost a la xicoteta localitat de Bunyol, a la província de València. Durant aquesta festa, milers de persones es reuneixen al carrer per a participar en una batalla gegantina amb tomaques madures. Es llancen unes cent vint tones de tomaques en menys d''una hora! L''origen de la festa es remunta a l''any 1945. Sembla que tot va començar per casualitat, durant una baralla entre joves al mig d''un mercat. Des d''aleshores, la tradició s''ha anat repetint cada any i ha esdevingut un esdeveniment internacional. Hui en dia, la Tomatina atrau persones de tots els racons del món, especialment de països com el Japó, Austràlia o els Estats Units. Per a participar en la festa, cal complir algunes regles bàsiques: cal aixafar les tomaques abans de llançar-les, no es pot llançar res més que tomaques, i cal parar quan sone el segon coet. Després de la batalla, els bombers netegen els carrers amb mànegues d''aigua i tothom va a banyar-se al riu o a casa. Encara que sembla un poc estrany, la Tomatina és una experiència única i molt emocionant que tothom hauria de viure almenys una vegada en la vida.',
'[{"pregunta":"¿Quan se celebra la Tomatina?","opciones":["L''últim dimecres d''agost","El primer dilluns de juliol","El 15 d''agost","El 25 de juliol"],"correcta":0},{"pregunta":"¿Quantes tones de tomaques es llancen?","opciones":["Cinquanta","Cent vint","Dos-centes","Cinc-centes"],"correcta":1},{"pregunta":"¿En quin any va començar la festa?","opciones":["1945","1965","1985","2005"],"correcta":0},{"pregunta":"¿Què cal fer abans de llançar les tomaques?","opciones":["Llavar-les","Aixafar-les","Pelar-les","Tallar-les"],"correcta":1}]'::jsonb),
('valenciano','eso','{2}','La meua ciutat: Alacant',
'Visc a Alacant, una ciutat del sud de la Comunitat Valenciana. Tinc tretze anys i n''estic molt orgullós perquè és una ciutat fantàstica per a viure. Alacant està a la vora del Mediterrani i té unes platges meravelloses. La més coneguda és la platja del Postiguet, que es troba just al centre de la ciutat. Té una sorra fina i daurada i un mar molt tranquil. A l''estiu, és impossible passar pel passeig sense parar a banyar-se. El símbol més important d''Alacant és el castell de Santa Bàrbara, que està a dalt d''una muntanya anomenada Benacantil. Des d''allà dalt, hi ha unes vistes increïbles de tota la ciutat i del mar. Pots pujar a peu, en cotxe o per un ascensor que travessa la muntanya. El castell és una construcció molt antiga, dels temps dels musulmans, i té molts segles d''història. Una altra cosa que m''agrada d''Alacant és el bon temps. Diuen que aquí hi ha més de tres-cents dies de sol a l''any. Per aquesta raó, la ciutat rep molts turistes, sobretot a l''estiu. La meua festa preferida són les Fogueres de Sant Joan, que se celebren del vint al vint-i-quatre de juny. Es planten enormes monuments al carrer i, l''última nit, es cremen tots en una espectacular festa del foc.',
'[{"pregunta":"¿Quina és la platja més coneguda d''Alacant?","opciones":["La Albufereta","El Postiguet","Sant Joan","La Almadrava"],"correcta":1},{"pregunta":"¿Com es diu la muntanya on està el castell?","opciones":["Benacantil","Aitana","Mont Cabeçó","Penyagolosa"],"correcta":0},{"pregunta":"¿Quants dies de sol té Alacant a l''any aproximadament?","opciones":["Més de 100","Més de 200","Més de 300","Més de 400"],"correcta":2},{"pregunta":"¿Quan se celebren les Fogueres de Sant Joan?","opciones":["Del 15 al 19 de març","Del 20 al 24 de juny","Del 14 al 19 d''agost","Del 9 al 12 d''octubre"],"correcta":1}]'::jsonb),
('valenciano','eso','{2}','Joanot Martorell i el Tirant',
'Joanot Martorell és un dels escriptors valencians més importants de la història. Va nàixer a Gandia cap a l''any 1410, en una família noble, i va ser cavaller. La seua obra més famosa és "Tirant lo Blanc", una novel·la cavalleresca escrita en valencià que va aparéixer per primera vegada l''any 1490. Aquesta obra és considerada una de les primeres novel·les modernes d''Europa i un dels grans clàssics de la literatura universal. "Tirant lo Blanc" conta les aventures d''un jove cavaller anglés anomenat Tirant, que viatja per Europa, África i Àsia per a defendre el cristianisme i lluitar contra els enemics. Al llarg de la seua vida, Tirant viu moltes batalles, troba l''amor i finalment mor de manera tràgica. La novel·la és molt extensa, però està plena d''acció, humor i sentiments. A diferència de moltes obres de l''època, els personatges de "Tirant lo Blanc" són persones realistes, amb defectes i virtuts. L''escriptor espanyol Miguel de Cervantes, autor d''"El Quixot", va dir que "Tirant lo Blanc" era el millor llibre del món i el va salvar quan el barber i el capellà cremaven els llibres de cavalleries de don Quixot. Aquest comentari ha donat al "Tirant" una fama internacional. Hui en dia, l''obra de Joanot Martorell es continua estudiant a les escoles i universitats de tot el món.',
'[{"pregunta":"¿Quan va aparèixer Tirant lo Blanc per primera vegada?","opciones":["1490","1390","1590","1690"],"correcta":0},{"pregunta":"¿De quina nacionalitat és el personatge Tirant?","opciones":["Valencià","Anglés","Francés","Italià"],"correcta":1},{"pregunta":"¿Què va dir Cervantes de Tirant lo Blanc?","opciones":["Que era avorrit","Que era el millor llibre del món","Que era massa llarg","Que no li agradava"],"correcta":1},{"pregunta":"¿On va nàixer Joanot Martorell?","opciones":["A València","A Gandia","A Castelló","A Alacant"],"correcta":1}]'::jsonb),
('valenciano','eso','{2}','Una eixida amb amics',
'El cap de setmana passat, vaig fer una eixida fantàstica amb els meus amics. Som un grup de cinc persones: Maria, Carles, Sara, Pau i jo. Volíem fer alguna cosa diferent, així que vam decidir anar a fer un dia de senderisme a la Serra Calderona, una zona muntanyosa molt bonica al nord de València. Vam quedar a les huit del matí a l''estació de tren. El viatge va durar uns quaranta minuts. Quan vam arribar al poble de Segart, ja estàvem desperts i amb ganes de caminar. La ruta començava al costat d''una xicoteta església. El primer tram era fàcil, però després el camí pujava i es feia més difícil. Cap a les onze, ens vam parar per a esmorzar entre els arbres. Maria havia portat entrepans per a tots, i Pau havia comprat fruita i sucs. Vam continuar caminant fins al cim, on hi havia unes vistes espectaculars de tota la comarca. Vam fer moltes fotos i ens vam sentir molt orgullosos d''haver arribat fins allà. Per a baixar, vam triar un altre camí més curt i més suau. Cap a les sis de la vesprada, ja estàvem de tornada al tren. Aquell dia vaig aprendre que les millors experiències són aquelles que es viuen amb els amics.',
'[{"pregunta":"¿Quants amics formen el grup?","opciones":["Tres","Quatre","Cinc","Sis"],"correcta":2},{"pregunta":"¿On van anar de senderisme?","opciones":["Serra d''Espadà","Serra Calderona","Penyagolosa","Aitana"],"correcta":1},{"pregunta":"¿A quina hora van quedar al tren?","opciones":["A les set","A les huit","A les nou","A les deu"],"correcta":1},{"pregunta":"¿Què havia portat Maria?","opciones":["Fruita","Entrepans per a tots","Begudes","Galetes"],"correcta":1}]'::jsonb),
('valenciano','eso','{2}','Els valencians al món',
'Al llarg de la història, molts valencians han eixit del seu país per diferents motius. A finals del segle dinou i principis del vint, la pobresa va obligar molts valencians a emigrar cap a Amèrica, sobretot cap a Argentina, Cuba i Veneçuela. Aquests emigrants buscaven noves oportunitats per a millorar la seua vida i la de les seues famílies. La majoria treballaven en el camp o en xicotetes empreses i, amb el temps, van fundar comunitats valencianes en aquestes terres. Hui en dia, encara hi ha clubs i centres valencians a moltes ciutats americanes que conserven les nostres tradicions. Durant els anys cinquanta i seixanta, una nova generació de valencians va emigrar a països europeus com França, Alemanya o Suïssa per a treballar en fàbriques i en la construcció. Molts d''ells van enviar diners a casa per a ajudar les seues famílies a Espanya. Avui dia, l''emigració ha canviat. Els valencians que ixen del país solen fer-ho per estudiar a l''estranger o per buscar feines especialitzades. Hi ha valencians vivint a tot tipus de països, des d''Europa fins a Austràlia o el Japó. Aquesta diàspora ha contribuït a difondre la nostra cultura, la nostra llengua i les nostres tradicions per tot el món. També ha enriquit la nostra societat amb noves idees i experiències.',
'[{"pregunta":"¿Cap a on emigraven els valencians a finals del segle XIX?","opciones":["Cap a Àsia","Cap a Amèrica, sobretot Argentina, Cuba i Veneçuela","Cap a Àfrica","Cap a Oceania"],"correcta":1},{"pregunta":"¿En quins anys van emigrar a països europeus?","opciones":["20-30","50-60","80-90","2000-2010"],"correcta":1},{"pregunta":"¿Per què emigren els valencians actualment?","opciones":["Per fugir de la guerra","Per estudiar a l''estranger o buscar feines especialitzades","Per la pobresa","Per a passar les vacances"],"correcta":1},{"pregunta":"¿Què conserven els clubs valencians a Amèrica?","opciones":["Les receptes de cuina","Les tradicions valencianes","Solament la llengua","Solament la música"],"correcta":1}]'::jsonb),
('valenciano','eso','{2}','Una recepta tradicional: la fideuà',
'Si penses que l''únic plat famós de la Comunitat Valenciana és la paella, t''equivoques. Hi ha un altre plat molt important que també forma part de la nostra cuina tradicional: la fideuà. La fideuà és semblant a la paella, però en lloc d''arròs porta fideus. És originària de la ciutat de Gandia, a la costa de València. Conta la llegenda que la fideuà va nàixer per accident en una barca de pescadors, quan un cuiner es va quedar sense arròs i va decidir utilitzar fideus. El resultat va agradar tant que el plat es va popularitzar ràpidament. Per a fer una bona fideuà necessites uns ingredients bàsics: fideus gruixuts, gambes, calamars, escamerlans, peix, all, tomaca, oli d''oliva i caldo de peix. Tots els ingredients s''han de cuinar en una paella, igual que la paella d''arròs. Primer s''asaona el peix i el marisc, després s''afegeix el sofregit i finalment s''aboca el caldo amb els fideus. La fideuà es cuina en aproximadament vint minuts i es menja directament de la paella. Es pot acompanyar amb una salsa especial anomenada all i oli, feta amb all, oli i sal. Si véns a la Comunitat Valenciana, no pots marxar sense provar aquest plat deliciós. T''asseguro que t''encantarà!',
'[{"pregunta":"¿En què es diferencia la fideuà de la paella?","opciones":["En els fideus en lloc de l''arròs","En la salsa","En les verdures","En el plat"],"correcta":0},{"pregunta":"¿On va nàixer la fideuà?","opciones":["A València","A Gandia","A Alacant","A Castelló"],"correcta":1},{"pregunta":"¿Com diu la llegenda que va nàixer?","opciones":["Per casualitat, sense arròs en una barca","En un restaurant elegant","Per un concurs","Per un xef famós"],"correcta":0},{"pregunta":"¿Amb què s''acompanya?","opciones":["Amb arròs","Amb una salsa anomenada all i oli","Amb pa","Amb amanida"],"correcta":1}]'::jsonb),
('valenciano','eso','{2}','Els meus animals preferits: les abelles',
'Les abelles són uns insectes molt menuts, però fan una feina molt important per a la natura i per als humans. Sense les abelles, moltes plantes no podrien reproduir-se i la nostra alimentació seria molt més pobra. Les abelles s''encarreguen de la pol·linització, és a dir, del transport del pol·len d''una flor a una altra. Aquest procés és essencial per a la producció de moltes fruites, verdures i altres aliments. Sense la pol·linització de les abelles, no tindríem pomes, taronges, melons, ametles ni moltes altres coses que mengem cada dia. Els científics calculen que un terç dels aliments depenen, directament o indirectament, de les abelles. Les abelles també ens donen un altre tresor: la mel. La mel és un aliment dolç i nutritiu, però també té propietats medicinals. Les abelles produïxen la mel a partir del nèctar de les flors i la guarden a les ruscs per a alimentar-se durant l''hivern. A més, també fan altres productes valuosos com la cera o la gelea reial. Malauradament, les poblacions d''abelles estan disminuint a causa dels pesticides, la contaminació i la pèrdua del seu hàbitat. Per protegir-les, podem evitar productes químics als jardins i plantar flors silvestres. Cuidar les abelles és cuidar el nostre planeta.',
'[{"pregunta":"¿Per què són importants les abelles?","opciones":["Per la mel només","Pel transport del pol·len i la pol·linització","Per netejar","Per fer música"],"correcta":1},{"pregunta":"¿Quina part dels aliments depenen de les abelles?","opciones":["Una desena part","Un quart","Un terç","La meitat"],"correcta":2},{"pregunta":"¿Quins productes ens donen les abelles?","opciones":["Només mel","Mel, cera i gelea reial","Llet","Ous"],"correcta":1},{"pregunta":"¿Per què disminueixen les poblacions d''abelles?","opciones":["Per la calor","Pels pesticides, la contaminació i la pèrdua d''hàbitat","Per l''aigua","Per ser massa nombroses"],"correcta":1}]'::jsonb),
('valenciano','eso','{2}','Vida saludable',
'Tindre una vida saludable és molt important per a sentir-se bé i tindre energia cada dia. Hi ha tres aspectes fonamentals per a portar una vida sana: l''alimentació, l''exercici físic i el descans. L''alimentació ha de ser variada i equilibrada. Cal menjar de tot, però amb moderació. Els metges recomanen menjar fruites i verdures cinc vegades al dia, beure molta aigua, i evitar l''excés de sucre, sal i greixos. La dieta mediterrània, típica de la Comunitat Valenciana, és una de les més saludables del món. Es basa en l''oli d''oliva, els cereals, les hortalisses, els llegums i el peix. L''exercici físic també és essencial. No cal ser un esportista professional, però sí practicar algun esport o activitat física diversos dies a la setmana. Caminar, anar amb bicicleta, nadar o jugar al futbol amb els amics són excel·lents opcions. L''exercici ajuda a fortalecer el cos i a mantenir una bona forma física. Finalment, és molt important descansar bé. Els adolescents necessiten dormir entre vuit i nou hores cada nit. Dormir poc afecta la concentració, la memòria i l''estat d''ànim. També és convenient evitar les pantalles del mòbil o l''ordinador abans de dormir. Si seguim aquests consells, podrem viure més anys i, sobretot, viure millor.',
'[{"pregunta":"¿Quants pics al dia s''ha de menjar fruita i verdura?","opciones":["Tres","Quatre","Cinc","Set"],"correcta":2},{"pregunta":"¿Quina dieta es menciona com a saludable?","opciones":["La dieta vegana","La dieta mediterrània","La dieta nòrdica","La dieta baixa en greix"],"correcta":1},{"pregunta":"¿Quantes hores ha de dormir un adolescent?","opciones":["6-7","Entre 8 i 9","10-11","12 o més"],"correcta":1},{"pregunta":"¿Quins són els tres aspectes per portar una vida sana?","opciones":["Aliment, esport i medicines","Alimentació, exercici i descans","Lectura, esport i amics","Estudi, treball i descans"],"correcta":1}]'::jsonb),
('valenciano','eso','{2}','Sant Vicent Ferrer, patró del Regne',
'Sant Vicent Ferrer és el patró de la Comunitat Valenciana i un dels personatges més estimats del nostre poble. Va nàixer a València l''any 1350 i va morir a Vannes, a Bretanya, l''any 1419. Va ser un home molt religiós que va dedicar la seua vida a predicar pel món sencer. Era frare dominicà i tenia una fama enorme com a orador. Diuen que els seus sermons emocionaven a la gent fins a les llàgrimes i que aconseguia convèncer les persones més obstinades. Sant Vicent va viatjar per França, Itàlia, Suïssa i Espanya, sempre a peu, predicant en moltes llengües, encara que ell només parlava el seu valencià natal. Aquest fet és considerat un dels seus miracles més coneguts. La Comunitat Valenciana celebra Sant Vicent Ferrer el dilluns següent al diumenge de Pasqua, és a dir, el segon dilluns després del Diumenge de Rams. Aquest dia és festiu en tot el territori. Una de les tradicions més curioses és la representació dels miracles del sant pels xiquets als carrers de València. Es construeixen unes xicotetes cases anomenades "altars de Sant Vicent" i els xiquets, vestits amb robes especials, representen escenes de la vida del sant. És una manera molt bonica i original de mantenir viva la memòria d''aquest personatge històric tan important per al nostre poble.',
'[{"pregunta":"¿On va nàixer Sant Vicent Ferrer?","opciones":["A Gandia","A València","A Castelló","A Bretanya"],"correcta":1},{"pregunta":"¿Què era Sant Vicent?","opciones":["Un cavaller","Un frare dominicà","Un poeta","Un rei"],"correcta":1},{"pregunta":"¿Quin és considerat un dels seus miracles?","opciones":["Volar","Ser entés en moltes llengües parlant en valencià","Curar malalts","Resuscitar morts"],"correcta":1},{"pregunta":"¿Qui representa els miracles del sant pels carrers?","opciones":["Els capellans","Els xiquets","Els turistes","Els actors"],"correcta":1}]'::jsonb),
('valenciano','eso','{2}','El meu cap de setmana ideal',
'Cada cap de setmana intent fer activitats que m''agraden molt, perquè són els meus dies preferits de la setmana. El divendres a la vesprada, quan acabe les classes a l''institut, em sent feliç perquè tinc per davant tot el cap de setmana per a divertir-me. Normalment el divendres a la nit em quede a casa amb la meua família. Sopem alguna cosa especial, com pizza o sushi, i veiem una pel·lícula al sofà. És el meu moment preferit de relax. El dissabte de matí m''agrada llevar-me un poc més tard, cap a les nou. Després d''esmorzar, quede amb els meus amics. Fem moltes coses diferents: a vegades anem a la platja, altres vegades al cine, i si fa mal temps ens quedem a casa d''algú a jugar a videojocs o a veure sèries. El dissabte a la vesprada solem anar al centre comercial. Hi ha botigues, restaurants i fins i tot una bolera on a vegades anem a jugar. El diumenge de matí faig els deures que tinc per al dilluns. M''agrada acabar-los prompte per a tindre la vesprada lliure. Després, anem a dinar a casa dels meus iaios al poble. El meu iaio sempre prepara cocs valencians i ens conta històries divertides. El diumenge a la vesprada tornem a casa i preparem la motxilla per a l''institut. Encara que no m''agrada que s''acabe el cap de setmana, em sent content.',
'[{"pregunta":"¿Què fa el divendres a la nit?","opciones":["Estudia","Es queda a casa amb la família veient pel·lícules","Va al cine","Surt amb amics"],"correcta":1},{"pregunta":"¿A quina hora s''alça el dissabte?","opciones":["A les set","A les huit","Cap a les nou","A les deu"],"correcta":2},{"pregunta":"¿Quan fa els deures?","opciones":["El divendres","El dissabte","El diumenge de matí","El dilluns"],"correcta":2},{"pregunta":"¿Què prepara l''iaio al poble?","opciones":["Paella","Cocs valencians","Fideuà","Postres"],"correcta":1}]'::jsonb);

