INSERT INTO comprension_texts (subject_id, level, grades, title, text_content, questions) VALUES
('valenciano','eso','{4}','Jaume I, el Conqueridor',
'Jaume I, conegut com el Conqueridor, és una de les figures històriques més importants per al poble valencià. Va nàixer a Montpeller l''any 1208 i va morir a València el 1276. Va ser rei de la Corona d''Aragó durant més de seixanta anys i, sota el seu regnat, es va dur a terme la conquesta de València. La conquesta va començar el 1232 i va culminar el nou d''octubre de 1238 amb l''entrada de Jaume I a la ciutat de València. Aquest dia és celebrat encara hui com el Dia de la Comunitat Valenciana. Després de la conquesta, Jaume I va fundar el Regne de València, que va ser una entitat política independent dins la Corona d''Aragó. Va atorgar als seus súbdits un conjunt de lleis pròpies anomenades "Furs de València", que regulaven la vida política, econòmica i social del nou regne. Els Furs garantien drets importants als ciutadans i van donar al Regne de València una identitat pròpia. Jaume I va promoure també la repoblació del territori. Va portar colons d''Aragó, de Catalunya i del sud de França per a habitar les terres conquistades. Aquests colons van portar amb ells la seua llengua, que va arrelar al territori i ha donat lloc al valencià actual. La figura de Jaume I és estimada pels valencians, que veuen en ell el fundador de la seua identitat nacional. La seua tomba es troba al monestir de Poblet, a Catalunya. Cada nou d''octubre, els valencians celebren el seu llegat i recorden els orígens del seu poble.',
'[{"pregunta":"¿Quan va entrar Jaume I a València?","opciones":["1212","9 d''octubre de 1238","1276","1300"],"correcta":1},{"pregunta":"¿Com s''anomenen les lleis que va atorgar?","opciones":["Edictes Reials","Furs de València","Cartes Pobles","Constitucions"],"correcta":1},{"pregunta":"¿Què es celebra el 9 d''octubre?","opciones":["L''aniversari del rei","El Dia de la Comunitat Valenciana","La fundació de Catalunya","La caiguda de Granada"],"correcta":1},{"pregunta":"¿On està enterrat Jaume I?","opciones":["A la Catedral de València","Al monestir de Poblet","A Montpeller","Al Palau Reial"],"correcta":1}]'::jsonb),
('valenciano','eso','{4}','La Renaixença valenciana',
'La Renaixença va ser un moviment cultural i literari que va sorgir al segle dinou amb l''objectiu de recuperar i prestigiar la llengua i la cultura catalana, valenciana i balear, després de segles de decadència. Durant l''edat moderna, el valencià havia estat substituït pel castellà en els àmbits oficials, literaris i culturals. La situació es coneix amb el nom de "Decadència", una època en què la llengua pràcticament no es feia servir per a escriure obres literàries importants. La Renaixença va començar a Catalunya cap a la dècada de 1830 i, posteriorment, es va estendre al País Valencià i a les Illes Balears. Al País Valencià, la figura més rellevant del moviment va ser Teodor Llorente, un poeta i periodista nascut a València l''any 1836. Llorente va fundar el diari "Las Provincias" i va impulsar la creació de les "Llirs Florals", un certamen literari en valencià que reunia els millors poetes de l''època. La seua poesia, plena d''amor per la terra valenciana, els paisatges i la història, va inspirar moltes generacions d''escriptors. Tanmateix, la Renaixença al País Valencià va ser més limitada que a Catalunya. Molts intel·lectuals valencians escrivien en castellà i veien el valencià només com una llengua per a la poesia o el teatre popular, però no per a la prosa seriosa. Aquesta situació va canviar durant el segle vint amb l''aparició d''escriptors com Joan Fuster i Vicent Andrés Estellés, que van prestigiar definitivament la nostra llengua.',
'[{"pregunta":"¿Què va ser la Renaixença?","opciones":["Un moviment polític","Un moviment cultural per recuperar la llengua i la cultura","Una guerra","Una revolta"],"correcta":1},{"pregunta":"¿Com es coneix l''època anterior?","opciones":["Decadència","Renaixement","Revolució","Restauració"],"correcta":0},{"pregunta":"¿Qui va ser la figura més important de la Renaixença al País Valencià?","opciones":["Joan Fuster","Teodor Llorente","Ausiàs March","Vicent Estellés"],"correcta":1},{"pregunta":"¿Per què va ser limitada al País Valencià?","opciones":["Per falta de recursos","Perquè molts intel·lectuals encara escrivien en castellà","Per la guerra","Per la prohibició legal"],"correcta":1}]'::jsonb),
('valenciano','eso','{4}','La intel·ligència artificial',
'La intel·ligència artificial, coneguda amb les sigles IA, és una de les tecnologies més revolucionàries del nostre temps. Es tracta de la capacitat de les màquines per a realitzar tasques que tradicionalment necessitaven la intel·ligència humana, com aprendre, raonar, prendre decisions o reconèixer imatges i veus. Tot i que pot semblar una invenció recent, les arrels de la IA es remunten als anys cinquanta del segle vint, quan els primers científics van començar a investigar com fer pensar les màquines. En els últims anys, els avanços han estat espectaculars. Hui en dia, la intel·ligència artificial està present en molts aspectes de la nostra vida quotidiana: en els assistents virtuals dels nostres mòbils, en les recomanacions de pel·lícules de plataformes com Netflix, en els filtres de les xarxes socials, en els traductors automàtics i fins i tot en els cotxes autònoms. La IA pot oferir grans beneficis a la humanitat. En medicina, per exemple, està ajudant a diagnosticar malalties greus de manera precoç i a desenvolupar nous tractaments. En la lluita contra el canvi climàtic, pot millorar l''eficiència energètica i predir fenòmens meteorològics extrems. Tanmateix, també hi ha preocupacions importants. Molts experts adverteixen que la IA podria substituir milions de llocs de treball, especialment aquells que són repetitius o automàtics. També es planteja el problema de l''ètica: qui és responsable si una intel·ligència artificial pren una decisió equivocada? Per aquestes raons, és essencial que la societat reflexione sobre com utilitzar aquesta tecnologia de manera responsable, garantint el benestar de totes les persones.',
'[{"pregunta":"¿Quan van començar les investigacions sobre IA?","opciones":["Anys 30","Anys 50 del segle XX","Anys 80","Anys 2000"],"correcta":1},{"pregunta":"¿En quins àmbits ajuda la IA en medicina?","opciones":["Construir hospitals","Diagnosticar malalties precoçment i desenvolupar tractaments","Cobrar als pacients","Fabricar medicaments més barats"],"correcta":1},{"pregunta":"¿Quina és una preocupació important?","opciones":["Que la IA pugui substituir llocs de treball","Que sigui massa cara","Que sigui difícil d''usar","Que no funcione mai"],"correcta":0},{"pregunta":"¿Què cal garantir segons el text?","opciones":["Més màquines","Un ús responsable que garantesca el benestar","Menys escoles","Més diners"],"correcta":1}]'::jsonb),
('valenciano','eso','{4}','El Compromís de Casp',
'El Compromís de Casp és un dels esdeveniments més importants de la història medieval de la Corona d''Aragó. Va tenir lloc l''any 1412, quan el rei Martí l''Humà va morir sense deixar descendència legítima. Aquesta situació va crear una crisi successòria, perquè diversos candidats reclamaven el tron. Per evitar una guerra civil, els representants dels regnes de la Corona, és a dir, Aragó, Catalunya i València, van decidir reunir-se a la ciutat de Casp i triar un nou rei mitjançant un procés racional i pacífic. Es van escollir nou compromissaris, tres per cada regne, que van debatre durant mesos abans de prendre una decisió. Finalment, van triar Ferran d''Antequera, un príncep castellà de la família Trastàmara, que va passar a regnar amb el nom de Ferran I. Aquesta decisió va tindre conseqüències molt importants. Per primera vegada, una dinastia de Castella governava la Corona d''Aragó. A llarg termini, això va contribuir al procés que portaria a la unió dels regnes hispànics sota els Reis Catòlics, ja al segle quinze. El Compromís de Casp també és important perquè va ser un exemple molt avançat de resolució pacífica de conflictes. En una època en què les disputes successòries solien resoldre''s amb les armes, els regnes de la Corona d''Aragó van triar el diàleg i la negociació. Aquest esperit de resolució pacífica és valorat encara hui com un dels precedents més antics del que avui anomenem democràcia parlamentària.',
'[{"pregunta":"¿En quin any va tenir lloc el Compromís de Casp?","opciones":["1212","1412","1512","1612"],"correcta":1},{"pregunta":"¿Per què va caldre triar un nou rei?","opciones":["Per una guerra","Perquè Martí l''Humà va morir sense descendència","Per un cop d''estat","Per votació popular"],"correcta":1},{"pregunta":"¿Quants compromissaris van debatre?","opciones":["Tres","Sis","Nou","Dotze"],"correcta":2},{"pregunta":"¿Qui va ser triat com a nou rei?","opciones":["Pere III","Ferran d''Antequera","Joan II","Alfons V"],"correcta":1}]'::jsonb),
('valenciano','eso','{4}','La sostenibilitat i el canvi climàtic',
'El canvi climàtic és un dels reptes més grans als quals s''enfronta la humanitat en el segle vint-i-u. La temperatura mitjana del planeta està pujant a un ritme alarmant a causa de les activitats humanes, especialment l''emissió de gasos d''efecte d''hivernacle. La crema de combustibles fòssils, com el petroli, el carbó i el gas, és la principal causa d''aquesta crisi. Les conseqüències del canvi climàtic ja són visibles a tot el món: glaceres que es desfan, oceans que pugen, fenòmens meteorològics extrems com sequeres, inundacions i incendis forestals més freqüents i intensos. A la Comunitat Valenciana, els efectes són especialment preocupants. La nostra regió s''està veient afectada per estius més llargs i calorosos, hiverns més suaus i pluges més intenses i imprevisibles. Algunes platges valencianes ja han perdut metres d''arena per culpa de la pujada del nivell del mar. Davant d''aquesta situació, és necessari actuar de manera urgent. La sostenibilitat consisteix a viure d''una manera que no comprometa el futur del planeta. Això implica utilitzar energies renovables, com la solar o l''eòlica, reduir el consum d''aigua i d''electricitat, fer servir el transport públic en lloc del cotxe particular, i evitar el malbaratament d''aliments. També és important reduir el consum de productes que contaminen, com els plàstics d''un sol ús. Cada acció individual compta, però també és necessari que els governs prenguen decisions valentes per a protegir el medi ambient. El futur del planeta depèn de tots nosaltres.',
'[{"pregunta":"¿Quina és la causa principal del canvi climàtic?","opciones":["L''agricultura","La crema de combustibles fòssils","Els animals","Els volcans"],"correcta":1},{"pregunta":"¿Com es veu afectada la Comunitat Valenciana?","opciones":["Té més neu","Estius més llargs i calorosos i pluges més intenses","Hi ha menys turistes","Es congela el mar"],"correcta":1},{"pregunta":"¿Què es la sostenibilitat?","opciones":["Comprar més coses","Viure sense comprometre el futur del planeta","Fer més fàbriques","No menjar carn"],"correcta":1},{"pregunta":"¿Quines energies renovables s''esmenten?","opciones":["Nuclear","Solar i eòlica","Carbó","Petroli"],"correcta":1}]'::jsonb),
('valenciano','eso','{4}','La novel·la negra valenciana',
'La novel·la negra és un gènere literari molt popular hui en dia, que combina el misteri, el crim i la investigació. Tot i que els seus orígens es troben als Estats Units i al Regne Unit, la novel·la negra ha trobat també un lloc important a la literatura valenciana. En les últimes dècades, diversos autors valencians han escrit novel·les negres ambientades a les ciutats i als pobles del País Valencià, incorporant elements propis de la nostra cultura, la nostra llengua i els nostres paisatges. Una de les figures destacades és Ferran Torrent, nascut a Sedaví el 1951. Les seues novel·les estan ambientades a València i barreges la trama policíaca amb elements humorístics i una mirada crítica de la societat. La seua sèrie de novel·les protagonitzada pel detectiu Toni Butxana és un clàssic de la literatura valenciana contemporània. Les obres de Torrent han estat adaptades també al cinema i a la televisió, ampliant així el seu públic. Una altra autora important és Silvestre Vilaplana, que ha escrit nombrosos relats i novel·les amb intrigues complicades i personatges molt ben dibuixats. La novel·la negra valenciana té una característica especial: a més de la trama criminal, també retrata la societat valenciana, els seus problemes, les seues contradiccions i les seues virtuts. Llegir aquestes novel·les és una manera entretinguda de conéixer millor el nostre poble. Hui en dia, gràcies al seu èxit, cada vegada més joves s''acosten a la literatura en valencià a través d''aquest gènere.',
'[{"pregunta":"¿On té els seus orígens la novel·la negra?","opciones":["A França","Als Estats Units i al Regne Unit","A València","A Itàlia"],"correcta":1},{"pregunta":"¿Qui és Ferran Torrent?","opciones":["Un poeta","Un autor de novel·la negra valenciana","Un periodista","Un actor"],"correcta":1},{"pregunta":"¿Com es diu el detectiu protagonista de la sèrie de Torrent?","opciones":["Pep Garcia","Toni Butxana","Vicent Roig","Joan Pla"],"correcta":1},{"pregunta":"¿Què retrata la novel·la negra valenciana a més del crim?","opciones":["Només paisatges","La societat valenciana, els seus problemes i virtuts","Només la cuina","Només la història"],"correcta":1}]'::jsonb),
('valenciano','eso','{4}','La revolució industrial al País Valencià',
'La revolució industrial va arribar al País Valencià més tard que a altres zones d''Europa, però va tindre un impacte molt important en la transformació de la nostra societat. A la primera meitat del segle dinou, la majoria dels valencians vivien al camp i es dedicaven a l''agricultura tradicional. Els principals cultius eren el blat, l''oli i la vinya. Tanmateix, a partir de la segona meitat del segle, van començar a aparèixer les primeres fàbriques i les primeres indústries modernes. La indústria tèxtil va ser la primera a desenvolupar-se. A localitats com Alcoi i Onteniyent, es van instal·lar fàbriques de teixits que utilitzaven màquines per a produir grans quantitats de roba a un preu més baix. Alcoi, especialment, es va convertir en un dels centres industrials més importants d''Espanya. Els treballadors hi venien de tots els pobles propers buscant feina i una vida millor. Una altra indústria que va prosperar va ser la del paper, també a Alcoi. A Castelló es va desenvolupar la indústria ceràmica, que avui en dia continua sent un dels sectors econòmics més importants de la Comunitat Valenciana. La revolució industrial també va portar canvis socials profunds. Va aparèixer una nova classe social, la classe obrera, formada per persones que treballaven a les fàbriques en condicions sovint molt dures: jornades llargues, salaris baixos i poca protecció. Els treballadors van començar a organitzar-se en sindicats per a defensar els seus drets. Així va començar el moviment obrer, que ha tingut una llarga història al País Valencià.',
'[{"pregunta":"¿Quina indústria va ser la primera a desenvolupar-se?","opciones":["La ceràmica","La tèxtil","La metal·lúrgica","L''alimentària"],"correcta":1},{"pregunta":"¿On es va desenvolupar la indústria del paper?","opciones":["A Castelló","A Alcoi","A València","A Sagunt"],"correcta":1},{"pregunta":"¿Quina indústria és típica de Castelló?","opciones":["Tèxtil","Ceràmica","Tabac","Sucre"],"correcta":1},{"pregunta":"¿Com es van organitzar els treballadors per defensar els seus drets?","opciones":["En partits polítics","En sindicats","En cooperatives","En associacions"],"correcta":1}]'::jsonb),
('valenciano','eso','{4}','La gastronomia valenciana més enllà de la paella',
'La cuina valenciana és molt rica i variada, encara que sovint es pensa només en la paella. La nostra gastronomia inclou un munt d''altres plats deliciosos, fets amb productes de la terra i del mar. Un dels plats més tradicionals és l''arròs al forn, que es prepara en una cassola de fang i porta cigrons, botifarra, cansalada i tomaca. Es cuina al forn fins que l''arròs queda daurat per dalt. És un plat molt típic dels diumenges, especialment a l''interior del País Valencià. Una altra recepta clàssica és l''olla, una mena d''estofat amb verdures, llegums i diferents tipus de carn, com cigrons, mongetes, naps, carlotes, costella de porc i botifarres. És un plat ideal per als dies freds d''hivern. A les zones de la costa, els plats de peix i marisc són els protagonistes. Hi ha el suquet de peix, els arrossos amb peix com l''arròs a banda i, per descomptat, l''espardenyada o la gamba blanca de Dénia, considerada una de les millors gambes del món. Pel que fa als postres, els valencians tenim moltes especialitats. Els bunyols de carabassa són típics de les Falles i de l''Hivern. La coca de llanda, un pastís de llimona, és un dolç quotidià present a moltes cases. Els torrons de Xixona són mundialment famosos i no poden faltar a les taules de Nadal. I no podem oblidar l''orxata, una beguda freda feta amb xufla, originària d''Alboraia, perfecta per a combatre la calor de l''estiu acompanyada de fartons. La gastronomia valenciana és, en definitiva, un veritable festival de sabors per a descobrir.',
'[{"pregunta":"¿En què es cuina l''arròs al forn?","opciones":["En una paella","En una cassola de fang","En una olla","En una graella"],"correcta":1},{"pregunta":"¿De quina ciutat és famosa la gamba blanca?","opciones":["València","Dénia","Alacant","Castelló"],"correcta":1},{"pregunta":"¿De quina localitat són els torrons famosos?","opciones":["Xixona","Gandia","Sagunt","Cocentaina"],"correcta":0},{"pregunta":"¿Amb què es pren l''orxata?","opciones":["Galetes","Fartons","Xocolata","Pa"],"correcta":1}]'::jsonb),
('valenciano','eso','{4}','El moviment feminista',
'El moviment feminista és un dels moviments socials més importants dels últims segles. Té com a objectiu aconseguir la igualtat de drets i d''oportunitats entre dones i homes. Durant molt de temps, les dones han patit discriminacions importants en la societat. No tenien dret a votar, no podien estudiar a les universitats, no podien obrir comptes bancaris al seu nom i, en moltes professions, no podien treballar. La lluita feminista va començar al segle dinou amb un moviment anomenat sufragisme, que reclamava el dret de les dones a votar. Després d''anys de manifestacions, vagues i fins i tot empresonament d''algunes activistes, les dones van aconseguir aquest dret en molts països durant les primeres dècades del segle vint. A Espanya, les dones van votar per primera vegada l''any 1933, durant la Segona República, gràcies a la lluita de figures com Clara Campoamor. Però la lluita per la igualtat no es va aturar amb el dret de vot. Durant el segle vint, les dones han continuat reivindicant els mateixos drets que els homes en l''educació, la feina, el matrimoni i la vida pública. Avui en dia, encara queden moltes batalles per guanyar. La bretxa salarial entre dones i homes encara és gran a la majoria de països i la violència de gènere continua sent un problema molt greu. A la Comunitat Valenciana, com a altres llocs, hi ha moltes associacions feministes que treballen per a denunciar les desigualtats i promoure la igualtat. La lluita feminista no és només cosa de dones: és una lluita per una societat més justa per a tothom.',
'[{"pregunta":"¿Quan van votar les dones per primera vegada a Espanya?","opciones":["1900","1933","1945","1978"],"correcta":1},{"pregunta":"¿Qui va lluitar per aquest dret a Espanya?","opciones":["Clara Campoamor","Federica Montseny","Dolores Ibárruri","Pilar Primo de Rivera"],"correcta":0},{"pregunta":"¿Què demanava el sufragisme?","opciones":["Salaris iguals","El dret de les dones a votar","Estudis universitaris","Vacances pagades"],"correcta":1},{"pregunta":"¿Quins problemes encara hi ha hui?","opciones":["Cap","Bretxa salarial i violència de gènere","Solament problemes educatius","Solament problemes laborals"],"correcta":1}]'::jsonb),
('valenciano','eso','{4}','El cinema valencià',
'El cinema valencià té una llarga història i una identitat pròpia dins del panorama cinematogràfic espanyol. Els primers anys del cinema, a finals del segle dinou i principis del vint, ja hi havia activitat cinematogràfica al País Valencià, amb produccions modestes però amb gran entusiasme. Tanmateix, l''edat d''or del cinema valencià es va donar als anys vint i trenta del segle vint, quan València va arribar a tindre diversos estudis cinematogràfics importants. La Guerra Civil i la posterior dictadura franquista van suposar un cop dur per al cinema en valencià, perquè durant molts anys es va prohibir l''ús de la nostra llengua als mitjans audiovisuals. No obstant això, des de la transició democràtica, el cinema valencià ha experimentat un nou desenvolupament. S''han creat empreses productores, escoles de cinema i festivals especialitzats. Un dels més coneguts és el Festival Internacional de Cinema de València. També s''han fet pel·lícules en valencià que han aconseguit reconeixement nacional i internacional. Hi ha hagut directors valencians de gran talent com Luis García Berlanga, nascut a València en 1921, considerat un dels millors directors de cinema espanyol de tots els temps. Les seues pel·lícules, com "Bienvenido Mister Marshall" o "El verdugo", són clàssics del cinema mundial. Altres directors actuals com Vicente Aranda o Bigas Luna també han contribuït a posar el cinema valencià en el mapa. En els últims anys, gràcies a la televisió pública À Punt i al suport institucional, s''està produint més contingut audiovisual en valencià. Encara queda molt per fer, però el futur del cinema valencià es presenta esperançador.',
'[{"pregunta":"¿Quan va ser l''edat d''or del cinema valencià?","opciones":["Anys 50","Anys 20 i 30 del segle XX","Anys 80","Anys 2000"],"correcta":1},{"pregunta":"¿Quin director valencià famós es menciona?","opciones":["Almodóvar","Luis García Berlanga","Saura","Buñuel"],"correcta":1},{"pregunta":"¿En quin any va nàixer Berlanga?","opciones":["1900","1921","1945","1960"],"correcta":1},{"pregunta":"¿Com es diu la televisió pública valenciana?","opciones":["TV3","À Punt","Canal 9","Telemadrid"],"correcta":1}]'::jsonb);
